INSERT INTO "meta_claims" VALUES(254,'paper-96','verify_minimal_length_formula: L(n) = sum_{k=1}^{n} k! is verified for n=4,5 against known literature values.     n=4 -> 33 (Houston 2015)   n=5 -> 153 (Pennynill 2017 / Egan-Houston 2018)','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(255,'paper-96','verify_greedy_superpermutation_containment: Greedy algorithm produces valid superpermutations for n <= 5.     Note: greedy is a heuristic, not guaranteed optimal. We only verify   that the resulting string contains all permutations (containment).','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(256,'paper-96','verify_combinatorial_overlap_bounds: Overlap between consecutive permutations is at most n-1.     Trivial upper bound: n! * n (no overlap).   Lower bound from pigeonhole: at least n! + (n-1) symbols needed.','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(257,'paper-96','verify_n6_bounds: n=6 case is open. Conjectured L(6)=873, but best bounds are 864 <= L(6) <= 872.     The conjectured formula value exceeds the current upper bound, so either   the conjecture fails at n=6 or the upper bound is not tight.','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(258,'paper-96','verify_lattice_code_chain: Chain [1, 3, 7, 8, 24, 72] matches known mathematical counts:   - 24 = 4! (permutations of 4 symbols)   - 72 = number of E6 roots (standard Lie theory)','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(259,'paper-96','verify_asymptotic_constant_bounds: Asymptotic constant C satisfies 1 < C <= 1 + 1/e ~ 1.3679.     The theoretical upper bound comes from the factorial sum formula:   L(n) = sum_{k=1}^n k! = n! * (1 + 1/n + 1/(n*(n-1)) + ...)   For large n, the tail beyond n! is dominated by (n-1)!, giving   ratio -> 1 + 1/n -> 1 from above. The conjectured exact formula   gives L(n)/n! -> 1 + 1/e ~ 1.3679 as n -> infinity.','D','CodeLib','code_claims','1522633550b76816e0fa9196d8694beb060a08879d745e4702ab50e59a57e70d');
INSERT INTO "meta_claims" VALUES(260,'paper-97','verify_energy_conservation: Total energy in an EHX system is conserved: E = E_e + E_h + E_X + E_screen.','D','CodeLib','code_claims','61dda8f98b1e7f249b324a937eeb111e2d93a3edc1beaf00d84930a0f0728059');
INSERT INTO "meta_claims" VALUES(261,'paper-97','verify_exciton_binding_energy: Hydrogen-like exciton energy levels: E_n = -R / n^2, where R is the reduced Rydberg.     In natural units (R=1), this becomes E_n = -1 / n^2.   All levels must be negative (bound states).','D','CodeLib','code_claims','61dda8f98b1e7f249b324a937eeb111e2d93a3edc1beaf00d84930a0f0728059');
INSERT INTO "meta_claims" VALUES(262,'paper-97','verify_exergy_formula: Exergy (available work): E_x = E - T_0 * S.     At absolute zero, exergy equals total energy.   Exergy is always <= total energy for T_0 > 0.','D','CodeLib','code_claims','61dda8f98b1e7f249b324a937eeb111e2d93a3edc1beaf00d84930a0f0728059');
INSERT INTO "meta_claims" VALUES(263,'paper-97','verify_entropy_production_sign: In non-equilibrium thermodynamics, entropy production is non-negative.     Recombination, scattering, and diffusion are irreversible processes.','D','CodeLib','code_claims','61dda8f98b1e7f249b324a937eeb111e2d93a3edc1beaf00d84930a0f0728059');
