INSERT INTO "meta_claims" VALUES(803,'paper-43','The D4 → J3(O) weight map for generation 3 is non-surjective at both the bottom and top faces; the bottom is a partial bridge (like the charm), and the top is a full boundary element (outside the domain).','D','CrystalLib','claims','d17c289ab344d8b38fc7e0908e9c051ffb1764d3406100c9ee1a9e511c6fb9dd');
