INSERT INTO "meta_claims" VALUES(805,'paper-43','The generation-3 quark masses are consistent with the CKM matrix structure, but the CKM matrix itself is not derived from the lattice; it is an empirical input.','I','CrystalLib','claims','de3fc8a51b1c15ce1d79300f3688d1de67e629ee75af05de613bad0179c5cb2a');
