INSERT INTO "meta_claims" VALUES(807,'paper-43','The J3(O) lattice for generation 3 contains a sublattice of 3 elements (bottom, top, and the confinement boundary), and the top element is the unique one outside the fundamental domain.','D','CrystalLib','claims','380148259107a52e21da099630772b1bff8ee5f1250ded95fd1ff5ccffaa7347');
