INSERT INTO "meta_claims" VALUES(813,'paper-44','The confinement boundary perturbation offset for generation 1 is m_{u,d} ≈ 2–5 MeV, for generation 2 is m_s ≈ 95 MeV, for generation 3 is m_b ≈ 4.18 GeV, and for the top quark the boundary condition is violated (mass is free).','D','CrystalLib','claims','122111ab67d0ab48257e5bb1d61110f99354cf599faf88357992bde31e6103ee');
