INSERT INTO "meta_claims" VALUES(884,'paper-50','The CKM matrix V and PMNS matrix U are 3×3 unitary matrices. The CKM mixes 3 quark generations; the PMNS mixes 3 lepton generations. Both have 4 real parameters (3 angles + 1 CP-violating phase).','D','CrystalLib','claims','866534fa97d3c4d0c6a766498d3eec8cbc2880f3b9b8287cd89c030e096f8117');
INSERT INTO "meta_claims" VALUES(885,'paper-50','The CKM matrix is approximately diagonal: small off-diagonal elements (θ_12 ≈ 13.1°, θ_23 ≈ 2.4°, θ_13 ≈ 0.2°).','D','CrystalLib','claims','f692a9af476b95c0b10a9a8b9938e7060204a8c7c7e10aa55736004a6157bcde');
INSERT INTO "meta_claims" VALUES(886,'paper-50','The PMNS matrix has large mixing: θ_12 ≈ 33.4°, θ_23 ≈ 45°, θ_13 ≈ 8.5°.','D','CrystalLib','claims','4b357e3a576470043b1bfc900af4385caf5a13b1ae39b1ca994a3ea890195ea4');
INSERT INTO "meta_claims" VALUES(887,'paper-50','CP violation is present in both matrices. The CKM phase δ_CKM ≈ 69° is the source of CP violation in the quark sector. The PMNS phase δ_PMNS is unknown but being measured.','D','CrystalLib','claims','50eacf3836242b1b44a0cffc59718ee5a4833ec0d28b735ccb229dda779fee8e');
INSERT INTO "meta_claims" VALUES(888,'paper-50','The structural form of both matrices is from the 3-generation SU(3) action. The 3 trace-2 idempotents of J3(O) are the 3 generations; the S3 Weyl orbit generates the mixing.','D','CrystalLib','claims','f811ba5d84be04656f2aa6c787594f601e0c89a581d4faa40b1f48e30620fcec');
INSERT INTO "meta_claims" VALUES(889,'paper-50','The S3 Weyl orbit on the 3 trace-2 idempotents generates the mixing structure. The 6 permutations correspond to the 6 possible mixing patterns.','D','CrystalLib','claims','154dcc96bb478f7c9d5390c712c10b7ffded7f02a818413f90574a005a4c5a47');
INSERT INTO "meta_claims" VALUES(890,'paper-50','The SU(3) Weyl closure at depth 3 gives the unitary matrix structure. The closure brings the 3×3 conditional matrix into the S3 group ring with residual² = 0 over ℚ.','D','CrystalLib','claims','c8e757995632c024534231f65f733e7d1f2fd44631739f37975a547b3e19e83a');
INSERT INTO "meta_claims" VALUES(891,'paper-50','The F4 action stabilizes the mixing structure: the automorphism group of J3(O) contains the SU(3) subgroup that stabilizes one generation, and the mixing is the F4/SU(3) symmetric space.','D','CrystalLib','claims','b2d451a7beae0ac863eff67be6921bd093adec5347aca7563da294062a181e41');
INSERT INTO "meta_claims" VALUES(892,'paper-50','The magic square of Freudenthal–Tits provides the exceptional-algebraic substrate for the mixing. The E6 root system contains the mixing structure; the E8 root lattice is the unification substrate.','D','CrystalLib','claims','c77649f5f9a2caa9ad742ce6f684093b339616301833b42e66b5a010bab6ce38');
INSERT INTO "meta_claims" VALUES(893,'paper-50','The mixing hierarchy (small CKM angles, large PMNS angles) is determined by VOA weight differences between generations. Large Δw → small mixing; small Δw → large mixing.','D','CrystalLib','claims','8328b96c9ee8912019ccd96ecff229a771a720976099ba730b978f25df52ee52');
