INSERT INTO "meta_claims" VALUES(895,'paper-50','The CP-violating phase δ_CKM is the associator phase: δ_CKM = arg([e_u, e_c, e_t]) + arg([e_d, e_s, e_b]).','I','CrystalLib','claims','4dbbcec973d0f56bf7b31c835e1a81da3c26fdc9be66ffc485708d34c37e191e');
INSERT INTO "meta_claims" VALUES(896,'paper-50','The values of the CKM and PMNS matrices (angles and phases) are open. The structural form is derived but the specific numerical values require external calibration.','D','CrystalLib','claims','1a93ee00552ed42e4e3713a41ee2cab668eaed78abaa255d39bdadfde22c2014');
