INSERT INTO "meta_claims" VALUES(900,'paper-50','Mapped file claims extraction','D','CrystalLib','claims','c8f320d6cfb08a8cdb52199c8c5e2ca58cfcfc77194a3ee044c1dca23acd2118');
INSERT INTO "meta_claims" VALUES(901,'paper-51','BSM physics (supersymmetry, extra dimensions, string theory, etc.) is out of scope of the LCR series. The LCR substrate is the SM; BSM is external.','D','CrystalLib','claims','96011faeda7ab6d190930146e850a8a6532afdc7912e767399d1ac45ba9caa18');
INSERT INTO "meta_claims" VALUES(902,'paper-51','The 8 irreducible gaps (CKM numerics, particle VOA weights, Higgs mass derivation, Γ_72 landing, full Moonshine identification, unbounded Rule 30 non-periodicity, GR EFE identity, cosmogenesis) are all gaps within the SM. None require BSM physics to close.','D','CrystalLib','claims','8b108daf30e55658dcee76d8c9f6fc26281a4ef88f2845a232dd5867b735f59a');
INSERT INTO "meta_claims" VALUES(903,'paper-51','The 26 generating relations of ℒ are sufficient for the SM. No BSM axioms are needed.','D','CrystalLib','claims','be6869642c93cbe18676358d0d47b1b4417994d7cb9b7b659f5b252684cc5aa9');
INSERT INTO "meta_claims" VALUES(904,'paper-51','The SM is the target of the LCR series. The SM is the closed form of the LCR series.','D','CrystalLib','claims','973f5eacdf6a1b6561b80ea2b2a7f8835f300cd09d7f10ad41e7e196e6e57898');
INSERT INTO "meta_claims" VALUES(905,'paper-51','The mass and Yukawa sector is entirely SM-native. The mass matrix is the 3×3 Hermitian matrix in J3(O); the Yukawa couplings are the off-diagonal octonionic entries; the flavor symmetry breaking is the S3 Weyl orbit action.','D','CrystalLib','claims','de2a8a2b322f5cbea8cdab10f1daa7fbdee01b5b852b251616404b8c7b70309c');
INSERT INTO "meta_claims" VALUES(906,'paper-51','The SM fermion mass matrix is the 3×3 Hermitian matrix in the J3(O) atlas: diagonal entries are real masses (VOA weights), off-diagonal entries are octonionic Yukawa couplings.','D','CrystalLib','claims','ee9dc67d223b7e78a7c6a9527361c7de6b68ae2110fcb14cefb79087d15ea730');
INSERT INTO "meta_claims" VALUES(907,'paper-51','The 3 generations are in bijection with the 3 trace-2 idempotents of J3(O): generation 1 ↔ E_11 + E_22, generation 2 ↔ E_11 + E_33, generation 3 ↔ E_22 + E_33.','D','CrystalLib','claims','c25735510257c05da18e07b4d4106dbcdd4f233d689bf1fa4272428d5dc6ba3a');
INSERT INTO "meta_claims" VALUES(908,'paper-51','The Yukawa couplings are the off-diagonal octonionic entries of the J3(O) mass matrix. The 24 octonionic dimensions encode the 12 SM Yukawa couplings with 2-fold redundancy.','D','CrystalLib','claims','a1f8009470c54b065f47270983014168a8718d51fb52c96c1c28c4acd8f25a8e');
INSERT INTO "meta_claims" VALUES(909,'paper-51','The Yukawa derivation from the chart structure is open. The chart structure gives the form but not the values.','D','CrystalLib','claims','44737891277c8cfa7a530cc64094f05135022ae2c73dadb26dd0b4bfed275aad');
INSERT INTO "meta_claims" VALUES(910,'paper-51','The seesaw mechanism is the suppression of the off-diagonal entries in the J3(O) mass matrix. The neutrino mass entries are suppressed by 10^−12 relative to charged fermion entries.','D','CrystalLib','claims','e50105cce88b80226af2419a29eeb60bd2f4c687c38e51b4c45acfafc6c55af3');
INSERT INTO "meta_claims" VALUES(911,'paper-51','The flavor symmetry breaking is the S3 Weyl orbit action on the 3 trace-2 idempotents, breaking SU(3) flavor symmetry to the CKM/PMNS mixing matrices.','D','CrystalLib','claims','ecea71a768bea3236049007427a07cfffc8e10e26aa3a208f35077f45261632f');
