INSERT INTO "meta_claims" VALUES(916,'paper-52','BSM physics is external to the LCR series. The LCR substrate is the SM; BSM is a separate research program.','D','CrystalLib','claims','ce30b95db068a7e7fbcb86dfcc378916fb1131dd37b43a8de384e8626c3da3b3');
INSERT INTO "meta_claims" VALUES(917,'paper-52','The LCR series does not claim any BSM results: no supersymmetry, no extra dimensions, no string theory, no axions, no dark matter particles.','D','CrystalLib','claims','6db111b1daede529871d1400d426e0d98da5e42789a99343e7e2b20b8b3d35f1');
INSERT INTO "meta_claims" VALUES(918,'paper-52','The neutrino mass mechanism (the seesaw mechanism) is SM-native: it is encoded in the off-diagonal octonionic entries of J3(O) (Paper 51, Corollary 5.3) and does not require BSM physics.','D','CrystalLib','claims','4ad55d12b2ecd5b55ea7f73ff9a19edbe6f943b0580d16abb29e8dbc0a0e17e2');
INSERT INTO "meta_claims" VALUES(919,'paper-52','The LCR series is complementary to BSM research: the LCR series provides a closed-form language for the SM; the BSM community provides extensions beyond the SM.','D','CrystalLib','claims','f7f2aeb0532266e4bc8d7e72ae497797fdd27bd8e551fe8732f9d8f721a7bc74');
INSERT INTO "meta_claims" VALUES(920,'paper-52','The LCR framework provides BSM-agnostic insights into the neutrino mass sector: the mass matrix structure, the VOA weight assignment, and the Monster VOA constraints are all SM-native and do not assume BSM physics.','D','CrystalLib','claims','46e03e1ce15e558d2c62e8b72ddc73b86d1c852d35075298aebeab6fbaba1db5');
INSERT INTO "meta_claims" VALUES(921,'paper-52','The neutrino mass mechanism in the LCR framework is the seesaw mechanism encoded in the off-diagonal octonionic entries of J3(O). The light neutrino masses are suppressed by the small off-diagonal entries relative to the charged fermion masses.','D','CrystalLib','claims','eac869a7301e10a858dac079db37b2f1e76334d6084c9154f802530efd8fea94');
INSERT INTO "meta_claims" VALUES(922,'paper-52','The 3 neutrino mass eigenstates correspond to the VOA weights w = 1, 2, 3 (Paper 16, Theorem 4.1). The mass-squared differences are Δm²_ij = κ²(w_i² − w_j²) × 10⁻¹², where the factor 10⁻¹² is the cosmological suppression scale.','D','CrystalLib','claims','4ad447bff7cb5f175f206ea3ec2adb6d2cea4e59d81f0259167d7e169ea7b87b');
INSERT INTO "meta_claims" VALUES(923,'paper-52','The seesaw scale is the natural unit κ = 25.05 GeV in the LCR substrate: m_ν ~ κ²/M_heavy, where M_heavy ~ 10¹² GeV is the heavy right-handed neutrino mass.','D','CrystalLib','claims','97f2e0b929d7eefe2ce1c52d4e1b2a04f2a3ee4dc814bf74636fccc0fb794eb8');
INSERT INTO "meta_claims" VALUES(924,'paper-52','The PMNS matrix structure is the lepton-sector S3 Weyl orbit (Paper 4, Theorem 6.1; Paper 50, Theorem 3.1). The 3 lepton generations are the 3 trace-2 idempotents of J3(O), and the PMNS matrix is the unitary transformation between the flavor basis and the mass basis.','D','CrystalLib','claims','e608ca10c07e44472d06ce7324d06f9c1cca625d1cd420fd45f598a4b764a7cb');
INSERT INTO "meta_claims" VALUES(925,'paper-52','The PMNS matrix is the lepton-sector analog of the CKM matrix. Both are 3×3 unitary with 4 parameters (3 angles + 1 CP-violating phase).','D','CrystalLib','claims','ddd9aec200fb53fe2b12d9e12697594bb33f9b7be2fabab1cb0c6ce2e91d7d6a');
INSERT INTO "meta_claims" VALUES(926,'paper-52','The large mixing in the PMNS matrix (θ_12 ≈ 33.4°, θ_23 ≈ 45°) is the S3 orbit in the lepton sector: the S3 permutation acts more strongly on the lepton generations than on the quark generations, giving larger mixing angles.','D','CrystalLib','claims','4340452938f50b94a99671643460adfecdf5f97e7b1e62d507a84bada06b2216');
INSERT INTO "meta_claims" VALUES(927,'paper-52','The Monster VOA (Paper 27, Theorem 3.1) constrains the mass scales of the LCR framework. The McKay row 196884 = 196883 + 1 bounds the VOA weight grading. The Monster triple [47, 59, 71] with product 196883 bounds the algebraic complexity of the neutrino sector.','D','CrystalLib','claims','0d4da4e80a4bb6a986641dfa3910e052a95b40d8d45821c6597cff1d2dc81fd8');
INSERT INTO "meta_claims" VALUES(928,'paper-52','The Monster ceiling bounds the VOA weight assignment: the VOA weights cannot exceed the Monster module structure. The top quark weight w = 7 is well below the Monster ceiling.','D','CrystalLib','claims','5d9f0a5db8e4055039b577e76117c4e3ce66ce9de7e5ea7f4693259c1f1949de');
INSERT INTO "meta_claims" VALUES(929,'paper-52','The McKay row 196884 = 196883 + 1 is the mass-scale ceiling: the sum of the VOA weights of all SM particles cannot exceed 196884. The actual sum is much smaller (~100).','D','CrystalLib','claims','3459ed8ca898017cb49411d1c9aa27befdf3fed8f7fdf1d594face62a2afc597');
INSERT INTO "meta_claims" VALUES(930,'paper-52','The SM mapping file for LCR-52 does not exist; 1 claimed row is inferred, 1 open.','D','CrystalLib','claims','4cbbb81d76be6a497a8beabc8feae1b4774cb42434618559861354816d61299e');
INSERT INTO "meta_claims" VALUES(931,'paper-52','Mapped file claims extraction','D','CrystalLib','claims','257d2e97033c5fb0564c048015d3887ae374bb03964fc4458120d0d4d144ffe7');
INSERT INTO "meta_claims" VALUES(932,'paper-52','Mapped file claims extraction','D','CrystalLib','claims','6570a8856cbbaf3925984e78d50451374e7426e241a27cf6aa9ddb1c8823534a');
INSERT INTO "meta_claims" VALUES(933,'paper-52','Mapped file claims extraction','D','CrystalLib','claims','310a4af5d5e236b5e1a78acb6d13b8d5efbfcda12e0248c46b8447ac47076587');
INSERT INTO "meta_claims" VALUES(934,'paper-53','The Higgs mechanism is identified with the VOA excited weight 5 = Higgs (Paper 16). The mass is anchored by construction: m_H = 5 · κ · SCALE = 125.25 GeV.','D','CrystalLib','claims','73f5e550e2a526591fceafcc31ff563a42abe301eda8352d1cb710e9eb301745');
INSERT INTO "meta_claims" VALUES(935,'paper-53','The Higgs weight w = 5 is the first excited weight above the vacuum w = 0 that produces a stable particle. Lower weights (w = 1, 2, 3, 4) are not stable particles in the SM.','D','CrystalLib','claims','d1bc72a8a15a03c4915ec466633412a69e2c3da529ce028032c3ec7d76785cbc');
INSERT INTO "meta_claims" VALUES(936,'paper-53','The Higgs mass 125.25 GeV = 5 × κ × SCALE emerges from the chart structure (Paper 4, Theorem 5.1): the chart is the lattice code chain 1→3→7→8→24→72, and the Higgs weight w = 5 is the 5th rung of the ladder.','D','CrystalLib','claims','983d02c5a2ba6dc2c274df8b06a34795220bc254033598ce03f2e9cdbf3ad496');
INSERT INTO "meta_claims" VALUES(937,'paper-53','In the LCR cosmological framework, the Higgs field is the observer: the Big Bang = Higgs field observing itself. The Higgs field''s self-interaction potential is the self-observation operator.','I','CrystalLib','claims','fff383b6a2a8cc26336035a24e16e9918adc097b76e4a695f48d25028ced6abd');
INSERT INTO "meta_claims" VALUES(938,'paper-53','The Higgs mass 125.25 GeV is the first stable mass produced by the VOA correction structure. The Higgs is the first stable particle after the Big Bang.','D','CrystalLib','claims','8ed7f3b6dcd54e3a7ead408eb17a888daa88f967f5e6f00a38def4a8897cba57');
INSERT INTO "meta_claims" VALUES(939,'paper-53','The Higgs self-coupling λ ≈ 0.13 is the observer coupling: it measures the strength of the Higgs field''s self-observation.','I','CrystalLib','claims','3e7d31e43d472e3632d3af23d266cdd0aa0b18eac3e243ee84e7ac33238232c1');
INSERT INTO "meta_claims" VALUES(940,'paper-53','The Higgs field''s SU(2) doublet structure is connected to the J3(O) atlas (Paper 4, Theorem 3.1) via the exceptional Jordan algebra. The Higgs doublet is a point in the J3(O) manifold.','D','CrystalLib','claims','4077d96863471b89c48d2df80744a741e73329b3fa65da27c198c781d445f60e');
INSERT INTO "meta_claims" VALUES(941,'paper-53','The quartic coupling λ_SM = m_H²/(2v²) ≈ 0.13 is computed from the trace-form potential and is consistent with PDG 2024.','D','CrystalLib','claims','a1a8502b90cb6282222f02525adcfdb9d74fc75d1638a8cb9f1ed565c693ee5c');
INSERT INTO "meta_claims" VALUES(942,'paper-53','The Higgs potential is the geodesic distance from the vacuum to the Higgs state in the J3(O) manifold, where the metric is the Freudenthal metric g_ij = tr(∂_i X ∘ ∂_j X). The Christoffel symbols are the gauge couplings (Paper 56).','I','CrystalLib','claims','5f54ffe99a96374060e73af58a34c5b9614a410a753c55334851e2bf9cb017b2');
INSERT INTO "meta_claims" VALUES(943,'paper-53','The Higgs field''s SU(2) doublet structure is connected to the E6/E8 exceptional structure via the lattice code chain. The Higgs doublet is the 2-dimensional representation of SU(2) that appears in the E6 root system decomposition.','D','CrystalLib','claims','f083aaf841b52ba430e50208026b2992259bb1ffb6bd38802f89f97e6f6314cf');
INSERT INTO "meta_claims" VALUES(944,'paper-53','The Higgs sector VOA weights are structurally derived: photon γ = 0.0, W± = 3.5, Z = 4.0, Higgs H = 5.0. The Higgs mass m_H = 5 · κ · SCALE = 125.25 GeV is the anchor.','D','CrystalLib','claims','7e95496d7c9f4d4e6b0edce87b0b57726294e0323f76977f9e6aaf3890df9135');
INSERT INTO "meta_claims" VALUES(945,'paper-53','The Higgs self-coupling λ is related to the VOA weight difference: λ = ½(w_H/v)² · (κ · SCALE)² ≈ 0.129, consistent with the SM value λ ≈ 0.13.','D','CrystalLib','claims','38895c96fef1adcb0cad28fe73bc7e24f9b350130ba09495915e92f0a8e6e055');
INSERT INTO "meta_claims" VALUES(946,'paper-53','The SM mapping file for LCR-53 does not exist; 12 claimed rows are inferred.','D','CrystalLib','claims','724cb367eb68043457534e1b7068f6807ceba809fc7fb1b081f42dc3c86a7690');
INSERT INTO "meta_claims" VALUES(947,'paper-53','The W/Z VOA weights are open (not yet assigned), and the cosmological interpretation of the Higgs as observer is the user''s framework, not yet derived from first principles.','D','CrystalLib','claims','c8bc84ba73351a792c5d210ac750d7d42d5a3998208e5f8c99f595afc72a54ca');
INSERT INTO "meta_claims" VALUES(948,'paper-53','Mapped file claims extraction','D','CrystalLib','claims','6fa30df9e6af11959b6bbf43bce3d551df7023ec0ed2fefc9daa263e5a85b40f');
INSERT INTO "meta_claims" VALUES(949,'paper-53','Mapped file claims extraction','D','CrystalLib','claims','049a2acae672934e6402bac77de437094fd64c8d94c356ad75255419d53466cd');
