INSERT INTO "meta_claims" VALUES(951,'paper-53','Mapped file claims extraction','D','CrystalLib','claims','59ee4d2fb510b381cd58024e66f9a15fac92c519d81b60fbb44e222835669d03');
INSERT INTO "meta_claims" VALUES(952,'paper-54','The VOA on the chart has excited states at weights 0, 5, 6, 7, 8, 9, ... The 5th excited state (weight 5) is the Higgs boson.','D','CrystalLib','claims','45cd80c2b4afc4f2c1e81110ea87f070b872060b0096e2cf646ed19ca5ca004c');
INSERT INTO "meta_claims" VALUES(953,'paper-54','The VOA weights on the chart are discrete integers: 0 (vacuum), 5 (Higgs), 6 (Higgs-like), 7, 8, 9, ... The weights are the natural grading of the lattice.','D','CrystalLib','claims','7f98f4cf692d59e4d6e4eec81fc082dc4ea09c416d3e5ddbe13b6bca2dcf0b97');
INSERT INTO "meta_claims" VALUES(954,'paper-54','The VOA weights are the lattice code chain (Paper 4, Theorem 5.1): the weights are the rungs of the ladder that correspond to the physical states. The chain 1→3→7→8→24→72 is the underlying structure.','D','CrystalLib','claims','31986082a4e08929a0e36f0d3362f2bdf5b6a05983f0b3f72bb009bd6da2ebec');
INSERT INTO "meta_claims" VALUES(955,'paper-54','The 5th excited state of the VOA is the Higgs. The mass is anchored by construction: m_H = 5 · κ · SCALE = 125.25 GeV.','D','CrystalLib','claims','e1ee016b03452e33a2bcc9a2235f21a7c5cc2fdf727584b8337d942c046b695f');
INSERT INTO "meta_claims" VALUES(956,'paper-54','The Higgs is the first massive excitation of the VOA: the vacuum (w = 0) is massless; the Higgs (w = 5) is the first state with a non-zero mass.','D','CrystalLib','claims','84cec88a2aedbe237cfabfa0dde14ef687f128becee03e97da5648ca634451c1');
INSERT INTO "meta_claims" VALUES(957,'paper-54','The Higgs mass 125.25 GeV is a prediction of the VOA structure: it is the mass of the 5th excited state, with the SCALE calibrated by the Higgs mass itself (circular anchor).','D','CrystalLib','claims','be4042180f8db0254fff8e86ccd69a227961fed642be3c99991a23f16b4c7854');
INSERT INTO "meta_claims" VALUES(958,'paper-54','The Higgs weight w = 5 is consistent with the Monster McKay row (Paper 90, Theorem 2.1): the McKay-Thompson coefficients c_n for n = 5 match the Higgs mass.','I','CrystalLib','claims','7821b3fcd38f135c3884bc8c6bd328f785830c7ed195726d535bd6df7785ef4f');
INSERT INTO "meta_claims" VALUES(959,'paper-54','The Monster VOA has coefficients that match the McKay-Thompson series. The VOA on the chart is a restriction of the Monster VOA to the chart''s states.','D','CrystalLib','claims','ccc5168231af4e844624bc2d6a33e15d383d26d024a97e066d804096da150fea');
INSERT INTO "meta_claims" VALUES(960,'paper-54','The Monster VOA is the ceiling structure of the LCR framework: it is the maximal VOA that contains all the physical states as restrictions.','D','CrystalLib','claims','ff4910241b6f0a8eadd5bcd2b7840846f9f3070dd0a53f83ec456a5ed8bb429e');
INSERT INTO "meta_claims" VALUES(961,'paper-54','The Higgs weight w = 5 is connected to the lattice code chain 1→3→7→8→24→72. The natural unit is 25.05 GeV; the Higgs is 5 units.','D','CrystalLib','claims','fdbb7ec119a75a62c8d32f7da71e1ff8001ef8c3be8348ca2777aa61683da150');
INSERT INTO "meta_claims" VALUES(962,'paper-54','The VOA excited state mass spectrum predicts confirmed states (w = 0, 3.5, 4.0, 5.0, 7.0) and open BSM candidates (w = 6.0, 8.0, 9.0, 10.0).','D','CrystalLib','claims','11759220c2dca6f4e57599d1ddf5c18e189e6cc170653510b520695a578572c9');
INSERT INTO "meta_claims" VALUES(963,'paper-54','The SM mapping file for LCR-54 does not exist; 3 claimed rows are inferred.','D','CrystalLib','claims','93aa03d878c25d3bf132315a7c085de950e6c6ac4ec5dc1a5b972e6f11d403cd');
INSERT INTO "meta_claims" VALUES(964,'paper-54','Mapped file claims extraction','I','CrystalLib','claims','4bb28412428884a7344390f6bcd9031d25683255464ae40eeebc4efa03ca3432');
INSERT INTO "meta_claims" VALUES(965,'paper-54','Mapped file claims extraction','I','CrystalLib','claims','4f9c76cf2cf9f2d83457575d5f856e06516791ed419ab54f32b18a13ee99e994');
INSERT INTO "meta_claims" VALUES(966,'paper-55','The vacuum stability requires λ > 0 at all scales. The SM renormalization group flow gives λ → 0 at ~10^10 GeV (the metastability scale).','D','CrystalLib','claims','0025eee70e97c3c73da300280d63f2e55da1727e1763aecedbf92a48d1a82aa2');
INSERT INTO "meta_claims" VALUES(967,'paper-55','The metastability scale is ~10^10 GeV, far above the electroweak scale (174 GeV) but far below the Planck scale (10^19 GeV).','D','CrystalLib','claims','556470377de26122076a99269dfb76dcdf7329b5bc84a9e2178609e6f4955592');
INSERT INTO "meta_claims" VALUES(968,'paper-55','The SM vacuum is metastable: the Higgs potential is bounded from below at the electroweak scale but becomes unbounded at high scales. The metastability is a consequence of the top quark Yukawa coupling.','D','CrystalLib','claims','e56c27a18d8523ac932c05e51bbba41b1ac47c73329b2ddcf8e68c94cf8086d9');
INSERT INTO "meta_claims" VALUES(969,'paper-55','The lifetime of the metastable vacuum exceeds the age of the universe (~13.8 Gyr), so the vacuum is effectively stable for all practical purposes.','D','CrystalLib','claims','5a474da8c97431dbe552d45bf9627bfa384008e4b1d0bb8827ac290f8865754a');
INSERT INTO "meta_claims" VALUES(970,'paper-55','In the LCR framework, the metastability is a boundary repair phenomenon (Paper 5): the electroweak scale is the "repaired" boundary where λ > 0; the high-scale region is the "unrepaired" region where λ < 0.','D','CrystalLib','claims','83b11fa1133cbef6ea0a449b715cb6729a82ad3231fcbef014cadbd0568d9610');
INSERT INTO "meta_claims" VALUES(971,'paper-55','The boundary repair operation (Paper 5) is the RG flow that keeps λ positive up to the metastability scale. The repair curvature K(v) is the RG flow of λ.','D','CrystalLib','claims','1384b2e128f5ef383c9e60cdb12e98d9db8fd1746eaa308d8e7859ac1bcd324f');
INSERT INTO "meta_claims" VALUES(972,'paper-55','The metastability scale (~10^10 GeV) is the repair boundary: beyond this scale, the repair curvature is insufficient and the boundary fails.','D','CrystalLib','claims','1c902bd09e4bc048e1422d9d4222c1d030b38e501b28db0a5327b6ce186bc54e');
INSERT INTO "meta_claims" VALUES(973,'paper-55','The vacuum energy is the mass residue (Paper 16) of the boundary repair: the energy that remains after the repair is the residual energy of the vacuum. The cosmological constant is this residual energy.','D','CrystalLib','claims','b186bd4591941142571457cc078f338c5788b6df46b9ac02355702e36ee11bc9');
INSERT INTO "meta_claims" VALUES(974,'paper-55','The cosmological constant problem is the discrepancy between the Higgs vacuum energy (~10^56 times the observed cosmological constant) and the observed dark energy density.','D','CrystalLib','claims','98938d0ce47dcb0bbd509d2cb20abaa363352580595a09345a194430a4a70657');
INSERT INTO "meta_claims" VALUES(975,'paper-55','In the LCR framework, the vacuum energy cancellation is the boundary repair (Paper 5) that removes the divergent zero-point energy. The zero-point energy is the sum of the VOA weights: Σ_w w · κ · SCALE.','D','CrystalLib','claims','593321b5056834a6b1605067eda07c15983b8654eb36627cec920c00ce436510');
INSERT INTO "meta_claims" VALUES(976,'paper-55','The SM vacuum is metastable at high energy because the Higgs self-coupling λ runs to negative values at high energy (~10^10 GeV). In the LCR framework, this corresponds to a VOA weight w > 5 having a lower energy state.','D','CrystalLib','claims','cf73ca031cf28a8c267208033f4e9f557a10bdec3bc417822787da476da33d25');
INSERT INTO "meta_claims" VALUES(977,'paper-55','The vacuum stability boundary is the w = 5 boundary: the vacuum is stable for w ≤ 5 and metastable for w > 5.','D','CrystalLib','claims','10e71af437ab9b7b2ffd57a7718ef9f9cc02c849e7d56ee6c691ecf99a933c5d');
INSERT INTO "meta_claims" VALUES(978,'paper-55','The top quark Yukawa coupling y_t ≈ 1 drives the RG flow. In the LCR framework, the top quark is the VOA weight w = 7 (open assignment). The Yukawa coupling is the coupling between the top quark (w = 7) and the Higgs (w = 5).','D','CrystalLib','claims','d90fcbe886752878fb9885a27d14de3dbba7ba1d0c48565d27f67ea219ff02cf');
INSERT INTO "meta_claims" VALUES(979,'paper-55','The top quark mass m_t ≈ 173 GeV is the VOA weight w = 7: m_t = 7 × 25.05 ≈ 175.35 GeV, close to the measured 173 GeV.','D','CrystalLib','claims','f0f8bea3125a1a75dcb6a8c1d2c5d482689be57d553476221719ad4aeb54e0b8');
INSERT INTO "meta_claims" VALUES(980,'paper-55','The SM mapping file for LCR-55 does not exist; 5 claimed rows are inferred.','D','CrystalLib','claims','97ee2edc6d29895c211d73d032bd64651ec6a4644f65dcc75ce19347fcfeb4ae');
INSERT INTO "meta_claims" VALUES(981,'paper-56','The Higgs couplings are proportional to the VOA weight differences: g_f = y_f × v = w_f × κ × SCALE · v/v.','D','CrystalLib','claims','1fcfa4cc3aa2a06bc93c7011638856e499da7484ed949051394a664db11b1a0a');
INSERT INTO "meta_claims" VALUES(982,'paper-56','The Higgs coupling to a fermion f is g_f = m_f × v/v. The coupling to a boson is g_V = m_V² × v/v.','D','CrystalLib','claims','f11b9e93ed1a5f9e7b3ad2d011e3559f4e01707f4b01650bae37aefe36846b0b');
INSERT INTO "meta_claims" VALUES(983,'paper-56','In the LCR framework, the Higgs couplings are determined by the VOA weight differences between the Higgs (w = 5) and the coupled state (w_f).','D','CrystalLib','claims','f66e2e929ea549d974fcac89eb0435dc0c57d1f66d071d6f75485312f6f0183c');
INSERT INTO "meta_claims" VALUES(984,'paper-56','The Higgs coupling to the top quark (w = 7) is the strongest: g_t = (7 − 5) × κ × SCALE = 2 × 25.05 = 50.10 GeV.','D','CrystalLib','claims','a02d70459b45f025ecb073dea9fa271b67e6b7c30879e23f4accb10e4550c52f');
INSERT INTO "meta_claims" VALUES(985,'paper-56','The Higgs coupling to the W boson (w = 3.5) is g_W = (5 − 3.5) × κ × SCALE = 1.5 × 25.05 = 37.58 GeV.','D','CrystalLib','claims','50867208f0875f3b9119fcde26f28e0aa29029569985385d22b7d62e9d13438c');
INSERT INTO "meta_claims" VALUES(986,'paper-56','The Higgs self-coupling λ = m_H² / (2v²) = 0.13. In the LCR framework, λ = (5 × κ × SCALE)² / (2v²).','D','CrystalLib','claims','51f629aadf3c247e3df21c128f98dbb69a8a74ef3992e8e9222f71b355e6bdd8');
INSERT INTO "meta_claims" VALUES(987,'paper-56','The Higgs couplings are the geodesic distances on the J3(O) manifold (Paper 53) between the Higgs state (w = 5) and the coupled state (w_f).','D','CrystalLib','claims','a1381435c5cd2b167bfcb139878f6e8226e28088d8c2b1296546266cbf4758ff');
INSERT INTO "meta_claims" VALUES(988,'paper-56','The Higgs couplings are the lattice code chain distances (Paper 4): the coupling to a state at weight w_f is the distance in the chain from the Higgs node to the node at w_f.','D','CrystalLib','claims','b320e007e07e8febaf207fb5a9ce3e0c4dc62837f482e15c660ea370d9ebf210');
INSERT INTO "meta_claims" VALUES(989,'paper-56','The Higgs coupling to the photon (γ) is loop-induced (γγ and γZ) and not directly proportional to a VOA weight difference.','D','CrystalLib','claims','83816ed4623ce50a41864a853b05ee32b96cf100ec3591c68f1dd09a25fb2538');
INSERT INTO "meta_claims" VALUES(990,'paper-56','The Higgs couplings to gluons (gg) are also loop-induced (via top quark loop) and not directly proportional to a VOA weight difference.','D','CrystalLib','claims','89bdb8b61092525c1d190f788a786252d0fae6332171ee09c716d6d289eaf41e');
INSERT INTO "meta_claims" VALUES(991,'paper-56','The Higgs decay widths are proportional to the square of the couplings: Γ_f = g_f² × m_H / (8π).','D','CrystalLib','claims','989fc981562cae0b50eb4d49268400afda867aea3e769b70440fdea7f5e9ccf1');
INSERT INTO "meta_claims" VALUES(992,'paper-56','The Higgs branching ratios are determined by the VOA weight differences: BR_f = Γ_f / Γ_total.','D','CrystalLib','claims','ebc32fff040a6d203d229a247b37594bfcdba1c0d61aa5e5184ab68870aaad84');
INSERT INTO "meta_claims" VALUES(993,'paper-56','The Higgs coupling deviations from SM predictions (e.g., in 2HDM) are mapped to VOA weight shifts: Δw = 6 would give a second Higgs with different couplings.','D','CrystalLib','claims','cb35215e1d50131238c50695fcecaaecb2f437fd5c086f0734354e84af66f600');
INSERT INTO "meta_claims" VALUES(994,'paper-56','The SM mapping file for LCR-56 does not exist; 4 claimed rows are inferred.','D','CrystalLib','claims','f6e4d839f6d786713c479dce00b42522a8a80afda0e2187f312c7df98b682be5');
INSERT INTO "meta_claims" VALUES(995,'paper-56','Mapped file claims extraction','I','CrystalLib','claims','df750c12f72ec9041ccb67ea497e6e061d3f847ea48d32b68ac13056b084d2ee');
INSERT INTO "meta_claims" VALUES(996,'paper-56','Mapped file claims extraction','I','CrystalLib','claims','b3f7eb348982fb222dc35d35253174d369409644afdac62c32722697e695af3e');
INSERT INTO "meta_claims" VALUES(997,'paper-57','Mesons are quark-antiquark bound states (q-q̄); baryons are 3-quark bound states (qqq). The hadron spectrum is the explicit mass and quantum number spectrum.','D','CrystalLib','claims','63f8dd21f6ddfaa7b8913c744fbeeb8dd888f53b0b4bb638ca428b5abdd971c5');
INSERT INTO "meta_claims" VALUES(998,'paper-57','The hadron spectrum is the QCD bound state spectrum: the strong force binds quarks into hadrons; the spectrum is the energy levels of the bound states.','D','CrystalLib','claims','1215cd6e925c4c56c59f59fae5503d3e1f7579075580b92397776c29c9d2959d');
INSERT INTO "meta_claims" VALUES(999,'paper-57','In the LCR framework, the hadron spectrum is the spectrum of the SU(3) color lattice (Paper 4): mesons are singlet and octet representations; baryons are singlet, octet, and decuplet representations.','D','CrystalLib','claims','22dbd7711201584934194f63c90b76b3eb2708536402847965b3573d1bdec932');
INSERT INTO "meta_claims" VALUES(1000,'paper-57','The quark model (Gell-Mann, Zweig 1964) classifies hadrons by quark content. Mesons: 3 ⊗ 3̄ = 1 ⊕ 8; baryons: 3 ⊗ 3 ⊗ 3 = 1 ⊕ 8 ⊕ 8 ⊕ 10.','D','CrystalLib','claims','b481f2af5c6609f9d6c100a5e24003343f5a6a0356e7537e4399ab65dd18f972');
INSERT INTO "meta_claims" VALUES(1001,'paper-57','The meson nonet (9 mesons) is the singlet + octet: π (triplet), K (doublet), η (singlet), η'' (singlet).','D','CrystalLib','claims','cc1f6c6d5af0ddac0f2ce29bc7141cf2459c842343980dba7f656fd9fc6e7784');
INSERT INTO "meta_claims" VALUES(1002,'paper-57','The baryon decuplet (Δ, Σ*, Ξ*, Ω) is the 10 representation of 3 ⊗ 3 ⊗ 3.','D','CrystalLib','claims','d17053d4986b0f43aa394f877f360756cecf8344a49ce90fa7226d0605725268');
INSERT INTO "meta_claims" VALUES(1003,'paper-57','The D4 codec (Paper 4, Theorem 5.1) encodes the 8 gluons as the 8 roots of the SU(3) adjoint representation. The D4 root system has 24 roots; the SU(3) subalgebra has 8 roots.','D','CrystalLib','claims','6efc5816f9ed50e54ce4bbe730b048ebc0bde0ae56107e075fde33fd541b1527');
INSERT INTO "meta_claims" VALUES(1004,'paper-57','The QCD running coupling α_s(Q²) = 4π/(β₀ ln(Q²/Λ²_QCD)) decreases with energy (asymptotic freedom).','D','CrystalLib','claims','7ec2c5010e1dfb41807cc876595bf8e1f56bac38c65f8e9eb942782e4f760e8d');
INSERT INTO "meta_claims" VALUES(1005,'paper-57','Asymptotic freedom is the boundary repair (Paper 5) at high energy: the color charge is the boundary type, and the running coupling is the repair curvature that removes the color charge at high scales.','D','CrystalLib','claims','75125e13e7255b8b5ab4bd3e929326ffb23a6dbd1762fdcb48b36ea825133bd5');
INSERT INTO "meta_claims" VALUES(1006,'paper-57','Perturbative QCD is the expansion in the repair curvature (Paper 5): Feynman diagrams are successive approximations to the boundary repair, and α_s is the expansion parameter.','D','CrystalLib','claims','8774b657e5ebcaf0d1bb2c7b00611de9e8ee83a2f94d6b200335ab0be7a74783');
INSERT INTO "meta_claims" VALUES(1007,'paper-57','The lattice code chain 1→3→7→8→24→72 underlies the QCD scale: 3 valence quarks → "3", 8 gluons → "8", 24 sea-parton species → "24".','D','CrystalLib','claims','4884d0b2102f2939e4e552a9f5757ab107d281454100916e3bbba89993250967');
INSERT INTO "meta_claims" VALUES(1008,'paper-57','The hadron masses are derived from the VOA weights of the constituent quarks: m_meson = w_q + w_q̄; m_baryon = w_q₁ + w_q₂ + w_q₃.','D','CrystalLib','claims','619f15d435b817d5d3ea58e39c323aead0b5694a424ae6032a6618d0e5ab2d99');
INSERT INTO "meta_claims" VALUES(1009,'paper-57','The pion mass is small because the up and down quark VOA weights are small.','D','CrystalLib','claims','baf47e5c3ad67a616a0c281c4b7dbf58095828e344e720a440bfa7610d764c87');
INSERT INTO "meta_claims" VALUES(1010,'paper-57','The Ω baryon mass is large because the strange quark VOA weight is large.','D','CrystalLib','claims','fb20382d66491e52df3036f44347e740b50d5ac08a877a29705603eb5e18bd35');
INSERT INTO "meta_claims" VALUES(1011,'paper-57','The SM mapping file for LCR-57 does not exist; 6 claimed rows are inferred.','D','CrystalLib','claims','e205164f76bd7d5a4494bedc81c6842b547cbc3fd636374baf67138e6f26340e');
INSERT INTO "meta_claims" VALUES(1012,'paper-57','Mapped file claims extraction','I','CrystalLib','claims','cc1df5d45b34673a788160a548de9c52ebd0edde0caac4b775bf193a892298b5');
INSERT INTO "meta_claims" VALUES(1013,'paper-57','Mapped file claims extraction','I','CrystalLib','claims','7338d295eec887d0e90772d4b3d08c3aedd30213bc4b865aecd8f78ba70f0df8');
INSERT INTO "meta_claims" VALUES(1014,'paper-58','The parton distribution functions (PDFs) f_i(x, Q²) give the probability density of finding parton i carrying momentum fraction x at resolution scale Q.','D','CrystalLib','claims','d44890127679bb29b8e1ce1ca13e7ac6a2ece1c2eb910eac511c3706e2e66832');
INSERT INTO "meta_claims" VALUES(1015,'paper-58','The DGLAP equations govern the scale dependence of PDFs.','D','CrystalLib','claims','70f50470a1cd81ac350431a64a6f4d92e5812dc590c4fb0a22bf54089ad2a758');
INSERT INTO "meta_claims" VALUES(1016,'paper-58','The proton PDFs decompose into 3 valence quarks (uud), a sea of q-q̄ pairs, and 8 gluon polarisations. The 3 valence quarks map to the "3" in the lattice code chain, the 8 gluons to the "8", and the 24 sea-parton species to the "24".','D','CrystalLib','claims','e0527ccb9b17cc62510144116b2acc9814218b2e21f71286b7765bc0895da913');
INSERT INTO "meta_claims" VALUES(1017,'paper-58','The hadron spectroscopy (Paper 57) is the boundary of the PDF evolution: hadrons are the color-singlet states that emerge at low Q, and PDFs are the parton-level description that resolves the hadron boundary.','D','CrystalLib','claims','47dc0d1b1e1b18ec3691ff46c72e39fbf3a892634f18d29a22938b8b82060efb');
INSERT INTO "meta_claims" VALUES(1018,'paper-58','In the LCR framework, the proton is a typed boundary (Paper 5) whose internal structure is repaired by the PDFs. The repair curvature at the parton level is the DGLAP splitting kernel P_ij(z); the boundary type is the proton quantum number (B=1, Q=1, I₃=+½).','D','CrystalLib','claims','c8477616cea2c25cefe6af7a5eb0e73cccad9d18441fa623be9ee06eed1b73bd');
INSERT INTO "meta_claims" VALUES(1019,'paper-58','The measured PDFs (CTEQ, MSTW, NNPDF) are the receipts (Paper 11) of the QCD repair process. Each PDF fit is a master-receipt stack entry that records the boundary state at a given scale Q.','D','CrystalLib','claims','6aa97cff1e673060fe57d6306e21c90fb4db6e904eab0732b3c8b2cf9e834c86');
INSERT INTO "meta_claims" VALUES(1020,'paper-58','The mesons (q-q̄) and baryons (qqq) (Paper 57) are the boundary types of the QCD typed boundary: mesons are the color-singlet quark-antiquark boundaries, and baryons are the color-singlet 3-quark boundaries.','D','CrystalLib','claims','7c43fd157237ade92604041dd35cd3765d697ade6e2cb84475b81ca3017f2ffe');
INSERT INTO "meta_claims" VALUES(1021,'paper-58','The lattice code chain 1→3→7→8→24→72 underlies the parton counting: 1 = proton, 3 = valence quarks, 7 = active parton species (3 quarks + 4 sea), 8 = gluon polarisations, 24 = sea-parton species (6 flavours × 4 helicities), 72 = total charged tracks in high-multiplicity event.','D','CrystalLib','claims','d300650accbf71c7b086d00c2191c45b4901fd0b130728a6eee91a4ffa09f1ff');
INSERT INTO "meta_claims" VALUES(1022,'paper-58','The PDF evolution is the boundary repair from the hadron boundary (low Q) to the parton boundary (high Q). The DGLAP equations are the repair curvature that removes the hadron boundary and reveals the parton boundary.','D','CrystalLib','claims','05edd8084e6c13ba31dcc0a640e394e67709e953dbcda2f42f400c682dddfc55');
INSERT INTO "meta_claims" VALUES(1023,'paper-58','The proton mass is the sum of the valence quark VOA weights plus the sea contribution: m_p = w_u + w_u + w_d + w_sea.','D','CrystalLib','claims','db89fc160b6dc9324a7988b6c4209738af8c67ad6a67f705726e1940b7c381a0');
INSERT INTO "meta_claims" VALUES(1024,'paper-58','The VOA natural energy scale 25.05 GeV (Paper 16) sets the hard-scale boundary for PDF evolution: Q² >> (25.05 GeV)² is the perturbative region; Q² << (25.05 GeV)² is the non-perturbative region.','D','CrystalLib','claims','f12cf387bea48cda60d58438730a5408bb30a6e849fbc8b18276a7b384123075');
INSERT INTO "meta_claims" VALUES(1025,'paper-58','The SM mapping file for LCR-58 does not exist; 5 claimed rows are inferred.','D','CrystalLib','claims','139532299ff7e42e38a9ef04ebdb3abf13f5bcbc282ee461d01c80135ad7491c');
INSERT INTO "meta_claims" VALUES(1026,'paper-58','Mapped file claims extraction','I','CrystalLib','claims','5586f9ee7e75f459490488dda36e7c7941cf3e7acad1761567fdc8ab1836d56d');
INSERT INTO "meta_claims" VALUES(1027,'paper-58','Mapped file claims extraction','I','CrystalLib','claims','fa32572e819ecb06f31756470ebcce958fed2067124a39abbd49a07b8ce3d1ce');
INSERT INTO "meta_claims" VALUES(1028,'paper-59','A jet is a collimated spray of hadrons produced by the hadronisation of a high-energy quark or gluon. The anti-kT algorithm clusters particles by the distance measure d_ij = min(p_T,i^-2, p_T,j^-2) ΔR_ij²/R².','D','CrystalLib','claims','095c21f0a904890003f72751d853aaaf5678a08fa683903985b88e7e026ce4d8');
INSERT INTO "meta_claims" VALUES(1029,'paper-59','The anti-kT algorithm is infrared and collinear safe.','D','CrystalLib','claims','171dd3874fd4b349b045be52b1cdabaa2b6ae07be1a0125f08f7c7e696f89c1b');
INSERT INTO "meta_claims" VALUES(1030,'paper-59','In a typical high-energy event the jet multiplicity follows the ladder 1→3→7→8→24→72: 1 hard parton, 3 jets, 7 hadrons, 8 stable species, 24 final-state particles, 72 charged tracks.','D','CrystalLib','claims','5d0632e0277589ffdaa0d55fdb343555483414ab06ee884931f6f6f472111e00');
INSERT INTO "meta_claims" VALUES(1031,'paper-59','The anti-kT algorithm is the computational repair operator (Paper 5): it clusters final-state particles into jets, reconstructing the original parton boundary from the hadron-level receipts.','D','CrystalLib','claims','08f4c6eb0929d33953df552b487be317271ab3a04a587e523b61505a48d4f421');
INSERT INTO "meta_claims" VALUES(1032,'paper-59','The fragmentation functions D_i^h(z, Q²) give the probability density that parton i fragments into hadron h with momentum fraction z at scale Q. They satisfy the momentum sum rule Σ_h ∫_0^1 dz z D_i^h(z, Q²) = 1.','D','CrystalLib','claims','1c7b438519f35451d53963c16c6231fbed712f79025f4962f2746a46cb093055');
INSERT INTO "meta_claims" VALUES(1033,'paper-59','The fragmentation functions are the bridge artifact (Paper 8) between the parton-level boundary and the hadron-level boundary. The bridge is one-way: partons → hadrons; the reverse is forbidden by confinement.','D','CrystalLib','claims','e8891a23116afcaaaf665058c9d82cc5b17294936d3244dc0889f71546fa5ea0');
INSERT INTO "meta_claims" VALUES(1034,'paper-59','The fragmentation functions are the receipts (Paper 11) of the boundary repair: they record the state of the hadron-level boundary after the parton-level boundary has been repaired.','D','CrystalLib','claims','04238d9da7ded2f34f573e05998676caffa48fcac50f17a463bcaca4ce513981');
INSERT INTO "meta_claims" VALUES(1035,'paper-59','In the LCR framework, a jet is a typed boundary repair (Paper 5): the high-energy parton boundary is repaired by the strong force into a cluster of hadrons.','D','CrystalLib','claims','eb0a6226434fb08262edcf5c848725f293cbcf31c3d1a75665aada9288650081');
INSERT INTO "meta_claims" VALUES(1036,'paper-59','The QCD phase transitions (quark-gluon plasma, color superconductivity) are the boundary repair at high temperature: the phase transition is the repair that removes the confinement boundary and restores the quark-gluon plasma.','D','CrystalLib','claims','14dd9315ca202070a6956888beee37d344f328370c18d1497734b2866ff912ca');
INSERT INTO "meta_claims" VALUES(1037,'paper-59','Lattice QCD (Paper 60) is the discrete model of the phase transition: the lattice is the discrete carrier, and the continuum limit is the boundary repair.','D','CrystalLib','claims','c69ca832f2d151b9f74eeeec5bf3d463f030bf3d926bdecc1c5ee096e3ff3533');
