INSERT INTO "meta_claims" VALUES(1694,'paper-97','The lattice code chain 1→3→7→8→24→72 (Paper 4) underlies the EHX structure: 1 = electron, 3 = hole states, 7 = exciton states, 8 = spin-charge combinations, 24 = exciton states (including spin and valley), 72 = electron-hole pairs (E6 roots, Paper 91).','I','CrystalLib','claims','9296d2aeb44e0b13ec991caeb94b40ad3250cf430b897fe81e7cdd096fe6567b');
INSERT INTO "meta_claims" VALUES(1695,'paper-97','The 72 E6 roots (Paper 91) are the 72 electron-hole pairs: each root corresponds to a distinct electron-hole configuration. The Niemeier glue Γ₇₂ glues the electron and hole into the exciton.','I','CrystalLib','claims','7b8c96ef1a32b23a3d83f418121871c1d4315e0d511e570e55794af81f9fa632');
INSERT INTO "meta_claims" VALUES(1696,'paper-97','The VOA weight assignment (Paper 16) anchors the exciton binding energy. The binding energy E_b = κ²/(2μ) · 10⁻⁹, where κ = 25.05 GeV is the natural unit and 10⁻⁹ is the solid-state suppression scale.','I','CrystalLib','claims','225b66bf0122765cebdc2805c7175547653e2eeaa8c0bb5f8b79c4b761643c9d');
INSERT INTO "meta_claims" VALUES(1697,'paper-97','The VOA weight assignment is the exergy anchor: the exciton binding energy is the exergy of the electron-hole pair, and the VOA weight gives the scale of the exergy.','I','CrystalLib','claims','02bc3a39a07977565288564c95af5be0ebc8cf9db7458884251ddd061ad25e1c');
INSERT INTO "meta_claims" VALUES(1698,'paper-97','The cosmological framework (Paper 100) is the ultimate energy balance: the Big Bang = Higgs observing itself is the initial energy state, and the EHX accounting is the local realization of the cosmological energy balance.','I','CrystalLib','claims','f634028a693288ce8c5cbc54e8a45ed7f1af4889630e048c4abd525e8bbb408f');
INSERT INTO "meta_claims" VALUES(1699,'paper-97','The capstone (Paper 100) validates the exergy analysis: the exergy of the EHX system is the local measure of the cosmological energy available for work.','I','CrystalLib','claims','331917e921ff63fdb0bd96ea78b10b0494e7521b6dcdb0a8d02edf58bea95b08');
