INSERT INTO "meta_claims" VALUES(1798,'paper-01','Theorem 8.1: The substrate map $T$ reproduces the canonical Rule 30 evolution at depth 4096 with 0 defects. *Proof.* The ANF equivalence $L \oplus C \oplus R \oplus C \cdot R = L \oplus (C \vee R)$ is verified by case analysis on $C$ and $R$. The T-substrate_map verifier runs canonical Rule 30 evolution from a s','D','CrystalLib','claims','9d0452032126ddbb2950089c4d87e81494f4da0102ca6e2d39137037f273a054');
INSERT INTO "meta_claims" VALUES(1799,'paper-02','Theorem 2.1: The Boolean identity establishing the ANF equivalence of Rule 30 over $\mathrm{GF}(2)$. 2. **Theorem 2.2 (Correction Surface Decomposition):** The Rule 30 = Rule 90 + correction decomposition, with the correction term firing on exactly two states. 3. **Theorem 2.3 (Lucas Bit Formula):** The closed f','D','CrystalLib','claims','279af6eb7dfd59ce6a2e8c49d40074d00ce085af75af829635482f0e13241925');
