INSERT INTO "meta_claims" VALUES(1801,'paper-02','Theorem 2.2: The Rule 30 transition decomposes as $$r_{30}(L, C, R) = r_{90}(L, R) \oplus \mathrm{correction}(C, R),$$ where $r_{90}(L, R) = L \oplus R$ and $\mathrm{correction}(C, R) = C \cdot \neg R$. *Proof.* By Theorem 2.1, the ANF of $r_{30}$ is $L \oplus C \oplus R \oplus (C \cdot R)$. The Rule 90 transiti','D','CrystalLib','claims','c9be9ab39f5af5ad1aa392af665908e073ead798fa2c67dbfed16eddaed31ba0');
INSERT INTO "meta_claims" VALUES(1802,'paper-02','Theorem 2.3: From a single-cell seed at position 0, the Rule 90 chart value at (depth $d$, offset $x$) is: $$a_d^{\mathrm{R90}}(x) = \mathrm{lucas\_bit}(d, x) = \begin{cases} 1 & \text{if } (d + x) \text{ is even, } k = (d + x)/2 \leq d, \text{ and } (k \,\&\, d) == k, \\ 0 & \text{otherwise.} \end{cases}$$ *Pro','D','CrystalLib','claims','4b2551c60c7401bbfc210ca22bd9b745525de28c23866e1ddb3894689b2f3f9f');
INSERT INTO "meta_claims" VALUES(1803,'paper-03','Theorem 3.1: The correction surface $S_{\mathrm{correction}} = \{(0, 1, 0), (1, 1, 0)\}$ consists of the two LCR states with $C = 1$ and $R = 0$, irrespective of the value of $L$. *Proof.* By definition, $\mathrm{correction}(C, R) = C \cdot \neg R = C \cdot (1 - R)$. This is 1 iff $C = 1$ and $R = 0$. For each s','D','CrystalLib','claims','4f49f55e26f62eb9752070c9d6986dc0aa496d36af020f1c995e00b8501ace9d');
INSERT INTO "meta_claims" VALUES(1804,'paper-03','Theorem 4.1: The bilinear form associated with $Q(L, C, R) = C + CR$ is $B_Q((L_1, C_1, R_1), (L_2, C_2, R_2)) = C_1 R_2 + C_2 R_1$, a non-degenerate bilinear form on the 2-dimensional $(C, R)$-subspace. *Proof.* By Definition 2.5, $$B_Q(u, v) = Q(u + v) + Q(u) + Q(v).$$ For $u = (L_1, C_1, R_1)$ and $v = (L_2, ','D','CrystalLib','claims','5593b7432aebc93d6c79d2268e107fe25a993893aa09ccd31f1d11c4f968de68');
INSERT INTO "meta_claims" VALUES(1805,'paper-03','Theorem 5.1: The Arf invariant of $Q(L, C, R) = C + CR$ is 0, i.e., $Q$ is hyperbolic. *Proof.* By Definition 2.6, the Arf invariant is $$\mathrm{Arf}(Q) = \sum_{v \in \{0,1\}^3} (-1)^{|v|} Q(v) \pmod{2}.$$ Evaluating $Q$ on all 8 inputs: | $v$ | $|v|$ | $(-1)^{|v|}$ | $Q(v)$ | contribution | |:---:|:---:|:---:|','D','CrystalLib','claims','750cf4fadf866b7476410a182b2da695776079ee54f89c02222d44c65898aacf');
INSERT INTO "meta_claims" VALUES(1806,'paper-03','Theorem 6.1: Two charts $C_1$ and $C_2$ with quadratic forms $Q_1$ and $Q_2$ on a shared boundary $\partial$ can be glued along $\partial$ if and only if $\mathrm{Arf}(Q_1|_{\partial}) = \mathrm{Arf}(Q_2|_{\partial})$. *Proof.* The Arf invariant is a topological invariant of the F2 quadratic form. Two F2 quadrat','D','CrystalLib','claims','0f52702125c8749681c451e78893acd44502f0a5fdac158c37435c90ad217226');
