INSERT INTO "meta_claims" VALUES(2036,'paper-07','DEFINITION Definition 1 — **Definition 1.1 (Closure-coherent sequence).** A binary sequence is *closure-coherent* if its chart''s `shell = 2` conditional transition matrix at `n = 3` is an exact element of the `S₃` group ring with residual squared less than `10⁻⁶` (in practice, exactly zero over `ℚ`).','D','CrystalLib','claims','7204ae8f668de75a3ea09e17f77c9a3199c10fb621bbabaa2f360c8a419e910d');
