INSERT INTO "meta_claims" VALUES(2100,'paper-03','Theorem 3.1: Local Triality Surface.** The map ```text tau(L,C,R) = (axis(L,C,R), sheet(L,C,R), diag(L,C,R)) ``` is a faithful three-language presentation of the eight binary LCR states. The axis/sheet part is a bijection from `S` to `{0,1,2,3} x {0,1}`. The diagonal part preserves shell as trace. The shell-2 states map to trace-2 diagonal idempotents.','D','CrystalLib','claims','e36a58d5f301ecd5f2b1342c570844ed8151560a1a8d54ecc4673f89dd11ff12');
INSERT INTO "meta_claims" VALUES(2101,'paper-03','Theorem 3.2: D4 Block Tower and Exceptional Conjugate Reapplication.** The local Paper 03 surface is now bound to the substrate D4 block, D4 block tower, and `G2 -> F4` T5 conjugate triple verifiers. This closes the paper-binding gap for those proven substrate mechanisms while preserving the distinction between the finite local registration theorem and any broader unrestricted exceptional-algebra claim.','D','CrystalLib','claims','15fd8804a4e3667b9c7c801c71fa1aa500905c2503bb93a3ee58d4d8ad6829ed');
INSERT INTO "meta_claims" VALUES(2102,'paper-03','Theorem 3.3: Algebra Foundation Stack.** The Paper 03 triality surface is paper-bound to the algebra-foundation receipts T1-T7: octonion axioms, `J3(O)` Jordan axioms, chart-to-`J3(O)` isomorphism, exact n=3 SU(3) Weyl closure, closure scale 3, identical trace-block closure, and the exact-rational 8x8 transition matrix.','D','CrystalLib','claims','4e4b15f35a42e3595b563e983c792057dd133c661ffeefc737ea855506a0cf1f');
