INSERT INTO "meta_claims" VALUES(2136,'paper-07','Theorem 7.1, Sample-Preserving Bridge. Every finite discrete trace over numeric values admits a continuous piecewise-linear bridge that exactly preserves all indexed samples.','D','CrystalLib','claims','742a72c6537638bf4249483bddbf6a3508ded27d355f8ed4709e907115ea04ab');
INSERT INTO "meta_claims" VALUES(2137,'paper-07','Theorem 7.2, MDHG/SpeedLight Retraction Bridge. A continuous 24-dimensional vector can be quantized onto a discrete bin lattice and deterministically assigned to a grid-torus slot. Re-admitting the same content is idempotent: `f(f(x)) = f(x)`. This makes the MDHG cache a replayable discrete-continuous retraction bridge. Product CA-field dynamics and empirical slot-collision claims remain outside this theorem.','D','CrystalLib','claims','053de4d88b20f90e7203979e60de6155e873f2bd9a5e122dbca71017d4c3a0a7');
