INSERT INTO "meta_claims" VALUES(2171,'paper-11','Theorem 11.1: T_ADMISSION.** Let `T` be a candidate theory with Gluon mass `m(T)`. Let `S_T10` be the trusted spectrum exposed by the Paper 10 master receipt, and let `K_max = 9`. Paper 11 admits `T` if and only if: ```text T10 signs the admission context m(T) in S_T10 m(T) <= K_max ``` If `T10` signs the context and `m(T) in S_T10` but `m(T) > K_max`, then `T` is routed to a boundary receipt. If `m(T) notin S_T10`, or if the candidate is not bound to the T10 context, the candidate is rejected or rejected as a datum according to the declared test.','D','CrystalLib','claims','824dd2c531774ce3187a087f389de4717cc21f9dcb8d936e6f8f3da6045f058f');
