INSERT INTO "meta_claims" VALUES(2188,'paper-13','Claim 13.7. `QuarkFaceForge` literalizes the structural color-transport surface: three colors, the `S_3` Weyl action, exact `n=3` `SU(3)` closure, trace conservation, the shell-2 chiral doublet, `J_3(O)` faces, and color confinement as an algebraic transport boundary.','D','CrystalLib','claims','d8485a3846b552b4744e2173befb7b6ab752ccb9928f69c58ec40db484a091ac');
INSERT INTO "meta_claims" VALUES(2189,'paper-13','Claim 13.8. Against published Standard-Model data (PDG/CODATA, retrieved 2026-06-14, no live measurement) the framework `SU(3)` color sector matches real QCD on four independent structural counts: three colors, eight gluons = adjoint = chart, `S_3` Weyl = color group, and six `A_2` roots = excited states. `alpha` and generation counts are suggestive/underived; the VOA mass partition does not map to the gauge-boson spectrum. That single non-match is a `2x2x2` vs `3x3` *basis* difference, not a failure (`3 x 3 = 9 = 8 (+) 1`; the chart `2^3 = 8` is the traceless adjoint, the standard `3 x 3` carries the trace/singlet), as closed in Paper 15. Numerical mass reconciliation via the trace correction is the remaining calibration.','D','CrystalLib','claims','6f88621d5cf24307183399d209f72a2fd532e080bb8202c7f696ef6598416006');
