INSERT INTO "meta_claims" VALUES(2211,'paper-16','Claim 16.3. Edge residue is exactly `C AND NOT R`, so it fires only at `(0,1,0)` and `(1,1,0)`.','D','CrystalLib','claims','1a6e18532d6d544bae5ad9425c6e371c7934650980ca98c362a604f61e21e688');
