INSERT INTO "meta_claims" VALUES(2214,'paper-16','Theorem 16 Continuum edge residuals are locally well-defined window receipts: ```text local state -> <=3-step rest closure -> edge_residue = C AND NOT R ``` and every global continuum claim remains an obligation until the propagating correction sum is closed.','D','CrystalLib','claims','1b0644dc9812510ffb899af818d6d7ee72c719bca0b75a756a37acfc495b403f');
INSERT INTO "meta_claims" VALUES(2215,'paper-17','Claim 17.1. The parameter chain `1,3,7,8,24` passes as the local-to-global code backbone.','D','CrystalLib','claims','3d7399a4596a59b45050b70a92f62dc09d78dc8891ad2ea0a5e1c47ce4010897');
