INSERT INTO "meta_claims" VALUES(2221,'paper-17','Claim 17.7. The Golay-to-Leech tower is constructively verified at the finite vector level: the extended Golay code has 4096 words and the lifted 24D even lattice has 196,560 constructed minimal vectors of norm 4.','D','CrystalLib','claims','92d25d57573a87abd1c3f791931ca0f3fd5ca4ac493b6afd2ad14979c1dce85b');
INSERT INTO "meta_claims" VALUES(2222,'paper-17','Theorem 17 The CQE error-correction tower has a verified bounded backbone: ```text local bit -> S3 neighborhood -> Hamming/Fano -> extended Hamming/E8 -> Golay ingredients -> Nebe-72 sheet bound ``` and its exceptional `E6/E7/E8` interpretation is admissible only as a transport reading over verified code and root-shell receipts, not as a completed physical or Leech-glue theorem.','D','CrystalLib','claims','ec02be4f5c82faeb66ae92d0cbac7abf331eb7f3a9c3d380bf63d3b5c367386c');
INSERT INTO "meta_claims" VALUES(2223,'paper-17','Theorem 17.2: Golay-to-Leech Vector Tower.** The extended binary Golay `[24,12,8]` code satisfies the Steiner `S(5,8,24)` octad property and lifts to a 24D even lattice with 196,560 constructed minimal vectors of norm 4. The constructed lattice supplies the finite Leech-facing tower layer. Identification with the unique Leech lattice, full unimodularity receipt, exhaustive pairwise closure, and 24D kissing optimality remain cited or future obligations.','D','CrystalLib','claims','47a879c1b07637dd248f5cf89341cbcdcc15caee0ce9af561cdd172ef71ebc13');
INSERT INTO "meta_claims" VALUES(2224,'paper-18','Claim 18.1. The finite centroid VOA seed partitions the eight chart states into two weight-0 vacua and six weight-5 excited states.','D','CrystalLib','claims','a0757fe759adcb54b3271833b6b3d2bcccb88ef7f9dfa4e344c7bb407d92df27');
