INSERT INTO "meta_claims" VALUES(2268,'paper-43','The bottom-quark mass (m_b ≈ 4.18 GeV at 2 GeV) is a residue of the generation-3 perturbation offset at the color-confinement boundary, with the B meson mass (M_B ≈ 5.28 GeV) reproduced by 4 × m_b ≈ 5.27 GeV within 0.2%.','D','PaperLib','claims','899a5f563e697fa3eab7bad57b0b526c5884e552cb0a9ef3f5f4173e4052e736');
INSERT INTO "meta_claims" VALUES(2269,'paper-43','The top-quark mass (m_t ≈ 173.1 GeV) is not predicted by the J3(O) lattice alone; it is a free perturbation parameter at the F4 boundary, bounded only by the requirement that the J3(O) error-correction cell remains valid.','I','PaperLib','claims','ca780e4c53bea2fb47e1e7d9f7dcd67a45e3a213f0de0f53098076091b65400b');
INSERT INTO "meta_claims" VALUES(2270,'paper-43','The top quark is the unique element where the J3(O) error-correction cell index equals the generation-3 anchor face, and the adjoint representation lies outside the J3(O) fundamental domain.','D','PaperLib','claims','8532be5f449bcce70d21f059c092de7f75c6d527014766933022f2f0e3ee8761');
INSERT INTO "meta_claims" VALUES(2271,'paper-43','The D4 → J3(O) weight map for generation 3 is non-surjective at both the bottom and top faces; the bottom is a partial bridge (like the charm), and the top is a full boundary element (outside the domain).','D','PaperLib','claims','b70e992291becf90e6ddbb94e04183a8200a86e6124d62cdf22e6407b0046b01');
