INSERT INTO "meta_claims" VALUES(2273,'paper-43','The generation-3 quark masses are consistent with the CKM matrix structure, but the CKM matrix itself is not derived from the lattice; it is an empirical input.','I','PaperLib','claims','07ef5b66d3e1735f7bb3a24d48608146ba30095984ddda0e2d9c1a475e78a9ef');
INSERT INTO "meta_claims" VALUES(2274,'paper-43','The SU(3) color-confinement boundary for generation 3 is the same as for generation 1 and 2, but the perturbation offset is larger because the J3(O) error-correction cell is further from the D4 lattice origin.','D','PaperLib','claims','d5eb00af11ade075197ecaf7e4939060c84b6f56ea89ed28fc19f88841e933e6');
INSERT INTO "meta_claims" VALUES(2275,'paper-43','The J3(O) lattice for generation 3 contains a sublattice of 3 elements (bottom, top, and the confinement boundary), and the top element is the unique one outside the fundamental domain.','D','PaperLib','claims','3f74850e4df243944a5566fcc954157d02a400925f402e744eff4cbfe5f229e4');
INSERT INTO "meta_claims" VALUES(2276,'paper-44','The D4 lattice color-confinement boundary is defined by the condition that the J3(O) error-correction cell index equals the F4 adjoint anchor face for the quark generation.','D','PaperLib','claims','682e9903347d27605487c49ae4e9be87c7c1281817a4401bedd32d2e32228618');
INSERT INTO "meta_claims" VALUES(2277,'paper-44','The color-confinement boundary is a uniform surface for all three quark generations, but the perturbation offset (quark mass) increases with generation number because the J3(O) cell is further from the D4 lattice origin.','D','PaperLib','claims','b5c4f09c615a993d8694851f3a457747ecb3189aa7a569ab71772567218639e6');
INSERT INTO "meta_claims" VALUES(2278,'paper-44','The confinement boundary perturbation offset for generation 1 is m_{u,d} ≈ 2–5 MeV, for generation 2 is m_s ≈ 95 MeV, for generation 3 is m_b ≈ 4.18 GeV, and for the top quark the boundary condition is violated (mass is free).','D','PaperLib','claims','04ed5d3c19dda406912d7fecf6bd4102a7029593673b1455c73e09c0fbbc7354');
INSERT INTO "meta_claims" VALUES(2279,'paper-44','The lattice closure theorem (Paper 8, Paper 8) implies that the color-confinement boundary is a closed surface in the D4 lattice, with the J3(O) cell providing the error-correction for the closure defect.','D','PaperLib','claims','82b6f2db3fd04340dc778750d82bcacd206ab64914e5008fb577a496d6033e86');
INSERT INTO "meta_claims" VALUES(2280,'paper-44','The SU(3) color charge is a residue of the D4 lattice root structure at the confinement boundary; the color charge magnitude is fixed by the root length, not by the quark mass.','D','PaperLib','claims','82ee847dc0628cf239d15b4a1d1351e39dc9f12a5deb62e99354580521d74048');
INSERT INTO "meta_claims" VALUES(2281,'paper-44','The color-confinement boundary for mesons (q-q̄ pairs) is the same as for baryons (qqq triplets) because the J3(O) cell index is generation-dependent, not color-representation-dependent.','D','PaperLib','claims','8012fb2e5fda7891c85591441e101f9ed26437b636e49261832df8e283f5c935');
INSERT INTO "meta_claims" VALUES(2282,'paper-44','The QCD coupling constant α_s at the confinement boundary is not predicted by the lattice; it is an empirical input. The lattice provides the boundary condition, not the coupling strength.','I','PaperLib','claims','b62c980735ad1cebcbba30c1a004176ed226c99c3c1b162a4cd10a5fda89ab00');
INSERT INTO "meta_claims" VALUES(2283,'paper-44','The confinement boundary is a smooth surface (no cusps) because the J3(O) error-correction cell is a smooth manifold.','I','PaperLib','claims','f88a63f84570c2482931fcb681f8354993cfd9133b3bcfbb7810c6491f5c009f');
INSERT INTO "meta_claims" VALUES(2284,'paper-44','The D4 lattice root structure implies that the color-confinement boundary has exactly 24 intersection points with the F4 adjoint line, one for each D4 root.','D','PaperLib','claims','63f1abfa49f39c520b2c1d0ea52df1fc921b7a873ad23cf4dc6fb152ce6ce39d');
INSERT INTO "meta_claims" VALUES(2285,'paper-44','The confinement boundary for the top quark is not defined because the top quark is outside the J3(O) fundamental domain; the QCD description of the top quark is perturbative, not confining.','D','PaperLib','claims','045810e5e188755c20ccb533a5be84d49f78fe0501fd553fd6be1cdc71162202');
INSERT INTO "meta_claims" VALUES(2286,'paper-45','The 4 electroweak gauge bosons (W+, W−, Z, γ) are the explicit SM translation of the D4 axis/sheet codec: 2 sheets (chiralities) + hypercharge phase (U(1) generator).','D','PaperLib','claims','5bc76ce5776b1b8f746dc0f324723cce17afadce8eefbd646c5bdf5d342932b2');
INSERT INTO "meta_claims" VALUES(2287,'paper-45','The W± and Z bosons are massive; the photon γ is massless and neutral. The 3 massive bosons acquire mass from the Higgs mechanism (Paper 46).','D','PaperLib','claims','e3d6c4566f0eda49d1a3910f87760ccb5ad9b5de90a9263e684a18ce9ff4cf8b');
INSERT INTO "meta_claims" VALUES(2288,'paper-45','The 2 sheets of the D4 codec are the 2 chiralities: sheet 0 = left-handed, sheet 1 = right-handed. The SU(2) weak interaction acts only on left-handed fermions (sheet 0).','D','PaperLib','claims','feca0a2dac9c0fe5849e06c7b36a8f9b78bd053acbc55a449d84d3ee59f2492c');
INSERT INTO "meta_claims" VALUES(2289,'paper-45','The D4 axis/sheet matching preserves the electroweak structure: boundary repair preserves chirality (sheet) and hypercharge (axis 0).','D','PaperLib','claims','4110feb611a25c837c24a773b4e008eda844938d6885678f6fa7f2b84d8242f8');
INSERT INTO "meta_claims" VALUES(2290,'paper-45','The Weinberg angle θ_W with sin²θ_W ≈ 0.2312 (PDG 2024) is the mixing between SU(2) and U(1). The exact value from the chart structure is open, requiring external calibration.','D','PaperLib','claims','8b064081d6ca609dc0d882b3a17321a190941da3d32d7cc7f9004588f16333a3');
INSERT INTO "meta_claims" VALUES(2291,'paper-45','The F4 exceptional Lie group contains SU(2) × U(1) as a subgroup. The full SM gauge group SU(3) × SU(2) × U(1) is embedded in F4.','D','PaperLib','claims','b6699f58f385c67dada7907c79fadce49bdca12bf4d18cc0a6b592018f6477f9');
INSERT INTO "meta_claims" VALUES(2292,'paper-45','The Freudenthal–Tits magic square contains SU(2) in the (ℝ, ℂ) and (ℂ, ℝ) entries, and SU(3) in the (ℂ, ℂ) entry, which contains SU(2) × U(1).','D','PaperLib','claims','57b4f1b9a34c521e6765bb0e638d167733d782d19993dc2f1ead06f0fb6d4af4');
INSERT INTO "meta_claims" VALUES(2293,'paper-45','The SM mapping file for LCR-45 does not exist; 13 claimed rows are inferred, not file-backed.','D','PaperLib','claims','d126b90c3e9de209d0daf5d8732ba5804a410378781444bca1920a6bdfd3c237');
INSERT INTO "meta_claims" VALUES(2294,'paper-46','The Higgs mechanism breaks the SU(2) × U(1) symmetry to U(1)_EM. The 3 W/Z bosons acquire mass (M_W = 80.4 GeV, M_Z = 91.2 GeV); the photon remains massless.','D','PaperLib','claims','da290bf1888f52aba7aa518cd9ad7822ef891207beb3fa22265f1f2402f5dde6');
INSERT INTO "meta_claims" VALUES(2295,'paper-46','The Higgs boson is the physical scalar remaining after the 3 Goldstone bosons are "eaten." Its mass is m_H = 125.25 GeV (Paper 16, VOA weight 5 = Higgs).','D','PaperLib','claims','575a3cce2702d15e4cc25b161106a28b03c14b772b3de66ca52e7f7ce16f6222');
INSERT INTO "meta_claims" VALUES(2296,'paper-46','The fermions acquire mass via Yukawa couplings to the Higgs field: m_f = y_f v / √2. The Yukawa couplings y_f are the 12 real parameters of the SM fermion mass sector.','D','PaperLib','claims','2fbb8731052aad6a4704fbc7c069165dc2e64288186d89257b052e7b8744331b');
INSERT INTO "meta_claims" VALUES(2297,'paper-46','The Higgs VEV v = 246 GeV is the substrate of the symmetry breaking. All masses generated by the Higgs mechanism are proportional to v.','D','PaperLib','claims','5ba5e94fa2137517ae5c7d7dcf7337ebb614dd0f9fac1a9cad5c814ca2485c14');
INSERT INTO "meta_claims" VALUES(2298,'paper-46','In the LCR framework, the electroweak symmetry breaking is a typed boundary repair (Paper 5). The Higgs VEV is the repair that gives mass to W and Z bosons.','D','PaperLib','claims','690eebb8fc9e8b7d16ba6e0c8263d9cdcd06f63d464169c8ebe053ee2b66dd80');
INSERT INTO "meta_claims" VALUES(2299,'paper-46','The boundary repair preserves the electromagnetic charge (axis 0 class of the D4 codec). The repair cannot change electromagnetic charge; it only gives mass to charged bosons.','D','PaperLib','claims','303730082ee5407d13442b24c0054571f8ccd96ef94ec999fc3fde58cf3317f1');
INSERT INTO "meta_claims" VALUES(2300,'paper-46','The repair count for the electroweak symmetry breaking is the repair curvature (Paper 5). The integrated repair count over the electroweak vacuum gives the vacuum energy density.','D','PaperLib','claims','b706c7749f4fce13b986f650306a9b11962a740d6761a0d3f9aaee799af920f4');
INSERT INTO "meta_claims" VALUES(2301,'paper-46','The symmetry-breaking repair is idempotent: applying the Higgs VEV twice is the same as applying it once. The vacuum is stable once the symmetry is broken.','D','PaperLib','claims','fe3ed110210f8ba696fcf79a8c1b3514b481de8ccb31b9bb04077a6735adc558');
INSERT INTO "meta_claims" VALUES(2302,'paper-46','The SM mapping file for LCR-46 does not exist; 9 claimed rows are inferred, not file-backed.','D','PaperLib','claims','fdfa13bdbab7e6764e48beb100325b157f8cbc8581c03b69ea2071bfa9affdc9');
INSERT INTO "meta_claims" VALUES(2303,'paper-46','The Higgs mass 125.25 GeV is the first stable mass produced by the VOA correction structure (Paper 53). The VOA weight w = 5 is the first excited weight producing a stable mass.','D','PaperLib','claims','2bad3048e65480fc116c0fc372638480a24301392e45400844100dc52678dbb4');
INSERT INTO "meta_claims" VALUES(2304,'paper-47','The V-A weak interaction is the selection of sheet 0 (left-handed) by the SU(2) weak interaction. The weak interaction acts only on left-handed fermions and right-handed anti-fermions.','D','PaperLib','claims','642d457592533977f687b08d7c1f7e0c06a214fcf24d4e7e06398438c500c1f4');
INSERT INTO "meta_claims" VALUES(2305,'paper-47','Right-handed fermions (sheet 1) do not participate in the weak interaction. The right-handed electron e_R, up quark u_R, and down quark d_R are singlets under SU(2).','D','PaperLib','claims','26163f90565b0a2f6eeecb71cbae2fff316e21574d06322f334d4ddd8871329c');
INSERT INTO "meta_claims" VALUES(2306,'paper-47','The V-A structure is universal: all fermions (leptons and quarks) participate in the weak interaction with the same V-A structure.','D','PaperLib','claims','3e6210499953ff48258392f31f3b89ae9d357a0ee95e57ba686d18489a093544');
INSERT INTO "meta_claims" VALUES(2307,'paper-47','Parity violation is maximal in the weak interaction. The mirror image of a weak process is not the same process. C and T are individually violated, but CPT is conserved.','D','PaperLib','claims','cfa73bfaff30fb132b105c1a7e8142c6dc46b636d91b8f3b419ebf532ffedc6f');
INSERT INTO "meta_claims" VALUES(2308,'paper-47','The CPT theorem is conserved in the LCR framework. The reversal involution (Paper 1) is the CP symmetry; the sheet value is the T symmetry. The combined operation is CPT.','D','PaperLib','claims','c5f047a5d5ad6966333a401916b1bb13ec4aa4127011e907474af091c06a7273');
INSERT INTO "meta_claims" VALUES(2309,'paper-47','The D4 axis/sheet matching (Paper 5) preserves the V-A structure: a boundary repair preserves the sheet value (chirality), ensuring left-handed fermions remain left-handed after repair.','D','PaperLib','claims','8cc8ce73c8a90598ec1313a1d3a20dc403436286add440812158d0c5e0aceb43');
INSERT INTO "meta_claims" VALUES(2310,'paper-47','The V-A structure is stable under boundary repairs: the weak interaction''s chirality preference is preserved by the typed boundary repair.','D','PaperLib','claims','1877a5734320723bdfa6705015b2a1ced2de1ac2fc533c4aae27becc0ec0f398');
INSERT INTO "meta_claims" VALUES(2311,'paper-47','The weak charged current is J^μ = ψ̄_L γ^μ τ^+ ψ_L, where τ^+ is the SU(2) raising operator. The current changes fermion flavor (e.g., e → ν_e, d → u).','D','PaperLib','claims','7a1067875717d0b1556b8248da00bc86006c499b8a072023e476df25c68f265f');
INSERT INTO "meta_claims" VALUES(2312,'paper-47','The SM mapping file for LCR-47 does not exist; 7 claimed rows are inferred, not file-backed.','D','PaperLib','claims','723e83a552a103999a3c048d71cde9c35a8f5721172180c888513d29bfe696aa');
INSERT INTO "meta_claims" VALUES(2313,'paper-47','The CP violation mechanism and neutrino mass/PMNS matrix are open obligations, not derived from the chart structure.','D','PaperLib','claims','24281ff1e4fbb51196114a942aea40b78e726d459c28db6b3173b725548189d0');
INSERT INTO "meta_claims" VALUES(2314,'paper-48','The electroweak phase transition at T_c ≈ 160 GeV is the boundary-repair threshold: above T_c, repair count is below threshold (symmetric phase); below T_c, repair count exceeds threshold (broken phase).','D','PaperLib','claims','34bed5aeffdf6476998606ed3f73901f484c80c7ad23e6a6d0dec07735288ffc');
INSERT INTO "meta_claims" VALUES(2315,'paper-48','In the symmetric phase (T > T_c), the SU(2) × U(1) gauge symmetry is unbroken; W, Z, and fermions are massless; repair count is below threshold.','D','PaperLib','claims','a8c93b922d0d63db7c55b45601899d905a4b618ebea39a10b206d554fdf391a8');
INSERT INTO "meta_claims" VALUES(2316,'paper-48','In the broken phase (T < T_c), the SU(2) × U(1) symmetry is broken to U(1)_EM; W and Z are massive; fermions acquire mass via Yukawa couplings; repair count exceeds threshold.','D','PaperLib','claims','8e053d638aa928e563d5c639c498edc574511557a4e39c93eac3b6fa43fc20ff');
INSERT INTO "meta_claims" VALUES(2317,'paper-48','The Higgs field at finite temperature has a temperature-dependent effective potential V_eff(φ, T). The minimum at φ = 0 is stable above T_c; the minimum at φ = v(T) is stable below T_c.','D','PaperLib','claims','385d59b2372c3e581bf99da5f05c6ddd21a35e4b17b7c3407ad9023213c18b91');
INSERT INTO "meta_claims" VALUES(2318,'paper-48','The W, Z, fermion, and Higgs masses are temperature-dependent and vanish at T_c.','D','PaperLib','claims','2713dfc2f9f119952d49cf3c351007a64aece24438a15516663c7b361301bc5c');
INSERT INTO "meta_claims" VALUES(2319,'paper-48','In the cosmological framework, the electroweak phase transition occurred approximately 10^−12 seconds after the Big Bang, when the universe cooled below T_c ≈ 160 GeV.','D','PaperLib','claims','e6644f470163decb4bf92ff55adaed9ce3e795ed5a8cde2878bcf4199371381f');
INSERT INTO "meta_claims" VALUES(2320,'paper-48','The QCD phase transition (T_c ≈ 150 MeV, t ≈ 10^−5 s) is after the electroweak phase transition in the thermal history.','D','PaperLib','claims','85d3b2e667728cb62bc7ff407ac99d58a9382afb59e15bb7acdee803dafe8e71');
INSERT INTO "meta_claims" VALUES(2321,'paper-48','The electroweak phase transition may explain baryogenesis if it is first-order; in the SM it is a crossover, so baryogenesis is not explained without extensions.','D','PaperLib','claims','318707dee8a0490128285201b19bc4b77cf8c7b1ee6f044e46a55f4a4a60c91f');
INSERT INTO "meta_claims" VALUES(2322,'paper-48','The lattice code chain 1 → 3 → 7 → 8 → 24 → 72 connects the electroweak phase transition to the exceptional structure: 24 (Leech lattice) is the cosmological substrate; 72 (E6 root system) contains the electroweak SU(2) × U(1).','D','PaperLib','claims','c11e2ecc0f881e8cde2fafb43779245773dd76176bb4894e1cccac299430d43e');
INSERT INTO "meta_claims" VALUES(2323,'paper-48','The SM mapping file for LCR-48 does not exist; 8 claimed rows are inferred, not file-backed.','D','PaperLib','claims','209a1302d389a2691297f833086b330503685d80a518fa04909fcaafcc2134ef');
INSERT INTO "meta_claims" VALUES(2324,'paper-48','The baryogenesis mechanism and first-order transition in extensions are open obligations.','I','PaperLib','claims','e3b07ba16915c429fc290ecb030fac267a0f7c557e7a15685f2abb4597000eb1');
INSERT INTO "meta_claims" VALUES(2325,'paper-49','The SM fermion mass hierarchy spans 6 orders of magnitude, from m_ν_e < 0.8 eV to m_t = 173.0 GeV.','D','PaperLib','claims','a2b08b09478846d8b4c982273a4838c024a72aee1295567117dc37053ce7075d');
INSERT INTO "meta_claims" VALUES(2326,'paper-49','The mass hierarchy is generation-ordered: generation 1 < generation 2 < generation 3 for each fermion type.','D','PaperLib','claims','d2c8748b20a88286bce83aed11832246b189dee4a027c2b482ab34c012c24211');
INSERT INTO "meta_claims" VALUES(2327,'paper-49','The quark masses are larger than the lepton masses within each generation (except top > tau), due to QCD confinement energy.','D','PaperLib','claims','92985756805dc0e3ec61214d301aab3229044ca081f51cf4c99f0db4dfd0eafd');
INSERT INTO "meta_claims" VALUES(2328,'paper-49','The neutrino masses are the smallest fermion masses, with the hierarchy (normal or inverted) open.','D','PaperLib','claims','5abddfbbca6f631dae5a245e0bbea1e5dd0d82e1a6a598546c87464880c6b252');
INSERT INTO "meta_claims" VALUES(2329,'paper-49','The VOA weight assignment gives the mass spacing: W = 3.5, Z = 4, top = 7, etc. The natural unit is 1 VOA unit = κ · SCALE ≈ 25.05 GeV. The empirical masses are consistent with the assignment to within order of magnitude.','D','PaperLib','claims','ed170abbaf63d6ffda3d800a1efa674e8a25d4a81645713e9f818eb31599e487');
INSERT INTO "meta_claims" VALUES(2330,'paper-49','The VOA weight assignment is hypothesized, not fully derived. The honest status is `structural_derivation_complete_numeric_calibration_pending`.','D','PaperLib','claims','029f1cc2acaa24c68fe2568a95896c21b29b2a0adb097fedc5202a51c5ede915');
INSERT INTO "meta_claims" VALUES(2331,'paper-49','The Higgs mass m_H = 5 · κ · SCALE = 125.25 GeV is the anchor of the mass hierarchy. All other masses are derived from the VOA weight assignment relative to this anchor.','D','PaperLib','claims','31a84b3e247c0b8ff749e253ae63a5737b7023e10e2abee676dd58d870709f36');
INSERT INTO "meta_claims" VALUES(2332,'paper-49','The SCALE ≈ 833 GeV is the energy scale of the VOA structure. The golden ratio φ = (1+√5)/2 is the structural constant with κ = ln(φ)/16 ≈ 0.0301.','D','PaperLib','claims','10fe6017c9e052be180339266e560050c0205596ffe6eaa600486a4d8f98677a');
INSERT INTO "meta_claims" VALUES(2333,'paper-49','The magic square of Freudenthal–Tits provides the exceptional-algebraic substrate for the mass hierarchy. The 3 trace-2 idempotents of J3(O) are the 3 generations.','D','PaperLib','claims','ecfa963df2ad4f428ecb5b8b60aabcfc1d75705ce36d7a7b2c702e2bf7fa4f74');
INSERT INTO "meta_claims" VALUES(2334,'paper-49','The E8 root lattice (248 roots) is the unification substrate containing all gauge groups and fermion representations.','D','PaperLib','claims','c4e198111f3212a91fa58d78c6b014e540476e03cab8d689296d970aa074ae9c');
INSERT INTO "meta_claims" VALUES(2335,'paper-49','The Yukawa derivation from the chart structure is open. The Yukawa couplings are the 12 real parameters of the SM fermion mass sector.','D','PaperLib','claims','e51e91aedfc601ead25923dcd600e516dc40af158f16370b07f46a344e6d7486');
INSERT INTO "meta_claims" VALUES(2336,'paper-49','The CKM and PMNS matrices are also open obligations.','D','PaperLib','claims','a9b989bd418d2bd690f925c988ba5ed2a47f40e01af726e07350af21f9482d5a');
INSERT INTO "meta_claims" VALUES(2337,'paper-49','The SM mapping file for LCR-49 does not exist; 5 claimed rows are inferred, 1 open.','D','PaperLib','claims','f67cc3afb853161998f84f7a77883cca3507c59997f86af00cb39b268b52ffe7');
INSERT INTO "meta_claims" VALUES(2338,'paper-49','The fermion VOA weight table predicts the top quark mass at 175.35 GeV (weight 7.0 × 25.05 GeV), within 1.5% of the empirical 172.76 GeV.','D','PaperLib','claims','4da69562fb579c11513e2f3b9a877308a6b4264ae0518e7dc0d76e14891f240d');
INSERT INTO "meta_claims" VALUES(2339,'paper-50','The CKM matrix V and PMNS matrix U are 3×3 unitary matrices. The CKM mixes 3 quark generations; the PMNS mixes 3 lepton generations. Both have 4 real parameters (3 angles + 1 CP-violating phase).','D','PaperLib','claims','4b1fad6897f01916e3b19fdbd0637446507999cd78d9d6b4f298130e3aa7619f');
INSERT INTO "meta_claims" VALUES(2340,'paper-50','The CKM matrix is approximately diagonal: small off-diagonal elements (θ_12 ≈ 13.1°, θ_23 ≈ 2.4°, θ_13 ≈ 0.2°).','D','PaperLib','claims','76442f96a9497507d28df84111ac648cf8a7772f4ad7a9e6b577349dd9616b86');
INSERT INTO "meta_claims" VALUES(2341,'paper-50','The PMNS matrix has large mixing: θ_12 ≈ 33.4°, θ_23 ≈ 45°, θ_13 ≈ 8.5°.','D','PaperLib','claims','95e61613d3a73375a47bc03c3b27681b31e30dd9366cb6261a1cdebe084f0de6');
INSERT INTO "meta_claims" VALUES(2342,'paper-50','CP violation is present in both matrices. The CKM phase δ_CKM ≈ 69° is the source of CP violation in the quark sector. The PMNS phase δ_PMNS is unknown but being measured.','D','PaperLib','claims','9d2bb821937d88ebbe76d333e467a1dd27b8aee52876e41f09f26a29f12114b3');
INSERT INTO "meta_claims" VALUES(2343,'paper-50','The structural form of both matrices is from the 3-generation SU(3) action. The 3 trace-2 idempotents of J3(O) are the 3 generations; the S3 Weyl orbit generates the mixing.','D','PaperLib','claims','85349f503d4b3faf19e3660745a65dcb4e985fa705b6d13a17646f084f6b9430');
INSERT INTO "meta_claims" VALUES(2344,'paper-50','The S3 Weyl orbit on the 3 trace-2 idempotents generates the mixing structure. The 6 permutations correspond to the 6 possible mixing patterns.','D','PaperLib','claims','357184115f87191ae33b4e22c45a828ed1214fed34e66c6d0d0428d6ea0f058e');
INSERT INTO "meta_claims" VALUES(2345,'paper-50','The SU(3) Weyl closure at depth 3 gives the unitary matrix structure. The closure brings the 3×3 conditional matrix into the S3 group ring with residual² = 0 over ℚ.','D','PaperLib','claims','6ee8e4046ce0597324a7b743ce4b2e0d42e51cb60d2488174fbb2a7d34051658');
INSERT INTO "meta_claims" VALUES(2346,'paper-50','The F4 action stabilizes the mixing structure: the automorphism group of J3(O) contains the SU(3) subgroup that stabilizes one generation, and the mixing is the F4/SU(3) symmetric space.','D','PaperLib','claims','1c06092c48c5ade487d7e559bbedaf2efc615dcc3cedc41763b0390f5a1ea982');
INSERT INTO "meta_claims" VALUES(2347,'paper-50','The magic square of Freudenthal–Tits provides the exceptional-algebraic substrate for the mixing. The E6 root system contains the mixing structure; the E8 root lattice is the unification substrate.','D','PaperLib','claims','8cfec9ba4c5957eb90e382e83fc355877ebf8c1244afce459272b1b7a00a822b');
INSERT INTO "meta_claims" VALUES(2348,'paper-50','The mixing hierarchy (small CKM angles, large PMNS angles) is determined by VOA weight differences between generations. Large Δw → small mixing; small Δw → large mixing.','D','PaperLib','claims','509356964f0991171b0bf9799a7b13216280232c781418e3ae80fb349b93e743');
INSERT INTO "meta_claims" VALUES(2349,'paper-50',').','I','PaperLib','claims','62359ae3da151f8d329b17f088da7d7b147f61c2902e56bbafd9615ba79102e5');
INSERT INTO "meta_claims" VALUES(2350,'paper-50','The CP-violating phase δ_CKM is the associator phase: δ_CKM = arg([e_u, e_c, e_t]) + arg([e_d, e_s, e_b]).','I','PaperLib','claims','c511b495b3aa4f911fb8c5fd2c4781c4937ea198071bde27c8ca82e62015163d');
INSERT INTO "meta_claims" VALUES(2351,'paper-50','The values of the CKM and PMNS matrices (angles and phases) are open. The structural form is derived but the specific numerical values require external calibration.','D','PaperLib','claims','fbcd2004d4a3da5bb6097c2d49521d3545cc4b32117a22855e14824e53ede76b');
INSERT INTO "meta_claims" VALUES(2352,'paper-50','The SM mapping file for LCR-50 does not exist; 1 claimed row is inferred, 1 open.','D','PaperLib','claims','7cb2d583ca1f950ddbca43b0acf885f5135eed0572af590e7b0fe9af041a23a2');
INSERT INTO "meta_claims" VALUES(2353,'paper-51','BSM physics (supersymmetry, extra dimensions, string theory, etc.) is out of scope of the LCR series. The LCR substrate is the SM; BSM is external.','D','PaperLib','claims','021336ba0ab2117f354d6d230d8b8b4c050303c78954751cd29b2554b1505023');
INSERT INTO "meta_claims" VALUES(2354,'paper-51','The 8 irreducible gaps (CKM numerics, particle VOA weights, Higgs mass derivation, Γ_72 landing, full Moonshine identification, unbounded Rule 30 non-periodicity, GR EFE identity, cosmogenesis) are all gaps within the SM. None require BSM physics to close.','D','PaperLib','claims','7ae18e3e0b36ac5089a0b26ddbd9081f23d1f7070ccf0d63dba8dd9cabde03ea');
INSERT INTO "meta_claims" VALUES(2355,'paper-51','The 26 generating relations of ℒ are sufficient for the SM. No BSM axioms are needed.','D','PaperLib','claims','0fd8d8173b00d46b48fd4ace6efa7a002e569cc7267a215f4ac51aab07b3583c');
INSERT INTO "meta_claims" VALUES(2356,'paper-51','The SM is the target of the LCR series. The SM is the closed form of the LCR series.','D','PaperLib','claims','c9a56ac618b92b5731391f382d7ffd452cf313d4a0023a1df92a97cfa67592bd');
INSERT INTO "meta_claims" VALUES(2357,'paper-51','The mass and Yukawa sector is entirely SM-native. The mass matrix is the 3×3 Hermitian matrix in J3(O); the Yukawa couplings are the off-diagonal octonionic entries; the flavor symmetry breaking is the S3 Weyl orbit action.','D','PaperLib','claims','ecc0d9c50390a00047fd33bde8bb2900c445b9b6a5fcdb0fed2a8a475b2d4ad0');
INSERT INTO "meta_claims" VALUES(2358,'paper-51','The SM fermion mass matrix is the 3×3 Hermitian matrix in the J3(O) atlas: diagonal entries are real masses (VOA weights), off-diagonal entries are octonionic Yukawa couplings.','D','PaperLib','claims','215e07b47da81557058f135837b8e5e7a4bdbc136d77c3ab79ab7846829b64f9');
INSERT INTO "meta_claims" VALUES(2359,'paper-51','The 3 generations are in bijection with the 3 trace-2 idempotents of J3(O): generation 1 ↔ E_11 + E_22, generation 2 ↔ E_11 + E_33, generation 3 ↔ E_22 + E_33.','D','PaperLib','claims','3b0e4d846b6f63e5dc6bedb2dd9db5dfd12cf5943b3a4a3e870926555b1418cf');
INSERT INTO "meta_claims" VALUES(2360,'paper-51','The Yukawa couplings are the off-diagonal octonionic entries of the J3(O) mass matrix. The 24 octonionic dimensions encode the 12 SM Yukawa couplings with 2-fold redundancy.','D','PaperLib','claims','752cf1d543ba5726b070a4a46552a3b055aef8dcfecf4d750597d63faf5ff759');
INSERT INTO "meta_claims" VALUES(2361,'paper-51','The Yukawa derivation from the chart structure is open. The chart structure gives the form but not the values.','D','PaperLib','claims','85d13ab732d70e3a325ccef7ca1a4638f46eea6d2cc1bff9d3e131a1ca64fc6e');
INSERT INTO "meta_claims" VALUES(2362,'paper-51','The seesaw mechanism is the suppression of the off-diagonal entries in the J3(O) mass matrix. The neutrino mass entries are suppressed by 10^−12 relative to charged fermion entries.','D','PaperLib','claims','3816e7290e7399fb74482b4a8c6893cb02200902f7fca4cc7c89c8067c048ebb');
INSERT INTO "meta_claims" VALUES(2363,'paper-51','The flavor symmetry breaking is the S3 Weyl orbit action on the 3 trace-2 idempotents, breaking SU(3) flavor symmetry to the CKM/PMNS mixing matrices.','D','PaperLib','claims','f4a6ffaf15d2cad68f4cf4b50702a9fac3d33ab171d20f2321b64556e312122b');
INSERT INTO "meta_claims" VALUES(2364,'paper-51','The SM mapping file for LCR-51 does not exist; 5 claimed rows are inferred.','D','PaperLib','claims','dfb30039f46dff3620e207209b632b8b63e9484b2821f8745a7e634c3ee07586');
INSERT INTO "meta_claims" VALUES(2365,'paper-52','BSM physics is external to the LCR series. The LCR substrate is the SM; BSM is a separate research program.','D','PaperLib','claims','a6cbd7b513474ea0cc2d8336f7e0d01cca55dc03bbf7fc8348e05b70b0ad95bc');
INSERT INTO "meta_claims" VALUES(2366,'paper-52','The LCR series does not claim any BSM results: no supersymmetry, no extra dimensions, no string theory, no axions, no dark matter particles.','D','PaperLib','claims','0990ca8d0e3da0040f2d4f7884c56788a4107d4e7a5ba4267e8873ca8b4fa7a4');
INSERT INTO "meta_claims" VALUES(2367,'paper-52','The neutrino mass mechanism (the seesaw mechanism) is SM-native: it is encoded in the off-diagonal octonionic entries of J3(O) (Paper 51, Corollary 5.3) and does not require BSM physics.','D','PaperLib','claims','9ba5fd2c07aaf02c83850a40ffeb1de7f0a7144d553befd3bd37e95f6e89cb8b');
INSERT INTO "meta_claims" VALUES(2368,'paper-52','The LCR series is complementary to BSM research: the LCR series provides a closed-form language for the SM; the BSM community provides extensions beyond the SM.','D','PaperLib','claims','a619c9ae9d4e5b08b2e5aece2d86f2fe5f8e4a8bb895f7f79e1733ac093020c1');
INSERT INTO "meta_claims" VALUES(2369,'paper-52','The LCR framework provides BSM-agnostic insights into the neutrino mass sector: the mass matrix structure, the VOA weight assignment, and the Monster VOA constraints are all SM-native and do not assume BSM physics.','D','PaperLib','claims','142c47f9c295e7f47dec78bb9fdcd880333a71f5e80286f226662bf11a7c097b');
INSERT INTO "meta_claims" VALUES(2370,'paper-52','The neutrino mass mechanism in the LCR framework is the seesaw mechanism encoded in the off-diagonal octonionic entries of J3(O). The light neutrino masses are suppressed by the small off-diagonal entries relative to the charged fermion masses.','D','PaperLib','claims','60040b5aeca335b2673a875546211233b9eb5b82c572ff241dbcf734520ffe15');
INSERT INTO "meta_claims" VALUES(2371,'paper-52','The 3 neutrino mass eigenstates correspond to the VOA weights w = 1, 2, 3 (Paper 16, Theorem 4.1). The mass-squared differences are Δm²_ij = κ²(w_i² − w_j²) × 10⁻¹², where the factor 10⁻¹² is the cosmological suppression scale.','D','PaperLib','claims','01fd95199b73fb2d6b05e6946dca3bba500f2b82897837b4a5624429ba7bdc90');
INSERT INTO "meta_claims" VALUES(2372,'paper-52','The seesaw scale is the natural unit κ = 25.05 GeV in the LCR substrate: m_ν ~ κ²/M_heavy, where M_heavy ~ 10¹² GeV is the heavy right-handed neutrino mass.','D','PaperLib','claims','22b8fff0b843a6f021e531a4baf2f458379cf267a5b63b4ef999d7bb08bfd6f8');
INSERT INTO "meta_claims" VALUES(2373,'paper-52','The PMNS matrix structure is the lepton-sector S3 Weyl orbit (Paper 4, Theorem 6.1; Paper 50, Theorem 3.1). The 3 lepton generations are the 3 trace-2 idempotents of J3(O), and the PMNS matrix is the unitary transformation between the flavor basis and the mass basis.','D','PaperLib','claims','8fc06b95897e42612415b8067609902538671465b29e6fbbf53eab12a5b16307');
INSERT INTO "meta_claims" VALUES(2374,'paper-52','The PMNS matrix is the lepton-sector analog of the CKM matrix. Both are 3×3 unitary with 4 parameters (3 angles + 1 CP-violating phase).','D','PaperLib','claims','b96d2c7e5cc3927f0854f559adff1c9f29d0030862bab398924e63963e5e8907');
INSERT INTO "meta_claims" VALUES(2375,'paper-52','The large mixing in the PMNS matrix (θ_12 ≈ 33.4°, θ_23 ≈ 45°) is the S3 orbit in the lepton sector: the S3 permutation acts more strongly on the lepton generations than on the quark generations, giving larger mixing angles.','D','PaperLib','claims','2ef476d50dc0525fb8f5d4abeae5b94e37d520ccdddffebb5ed21c6a9bc02c65');
INSERT INTO "meta_claims" VALUES(2376,'paper-52','The Monster VOA (Paper 27, Theorem 3.1) constrains the mass scales of the LCR framework. The McKay row 196884 = 196883 + 1 bounds the VOA weight grading. The Monster triple [47, 59, 71] with product 196883 bounds the algebraic complexity of the neutrino sector.','D','PaperLib','claims','8da50650f7f23d4ce9c9b2f69292595f6ca5c83349751718d42cbb95c70321fc');
INSERT INTO "meta_claims" VALUES(2377,'paper-52','The Monster ceiling bounds the VOA weight assignment: the VOA weights cannot exceed the Monster module structure. The top quark weight w = 7 is well below the Monster ceiling.','D','PaperLib','claims','33d3528428c4ac0bafe4775f3f90952765847d4cefab36775ba6e6ffc85c2b29');
INSERT INTO "meta_claims" VALUES(2378,'paper-52','The McKay row 196884 = 196883 + 1 is the mass-scale ceiling: the sum of the VOA weights of all SM particles cannot exceed 196884. The actual sum is much smaller (~100).','D','PaperLib','claims','32ad604fc19b932a13764c84a58f011f78d623a9c7c0156faf340ed6b1e6c3d8');
INSERT INTO "meta_claims" VALUES(2379,'paper-52','The SM mapping file for LCR-52 does not exist; 1 claimed row is inferred, 1 open.','D','PaperLib','claims','cc09a5c495aed6f7f40666a42eb0356e9381e3ddc2b92359965937086008560e');
INSERT INTO "meta_claims" VALUES(2380,'paper-53','= v/√2. The 3 Goldstone bosons are "eaten" by the W/Z; the 1 physical Higgs is at 125.25 GeV.','D','PaperLib','claims','f82941abca02bfffa56a8e0892670f95dee14b7bf0a5a31519aa17d35a440143');
INSERT INTO "meta_claims" VALUES(2381,'paper-53','⁴ term is the repair curvature that stabilizes the vacuum.','D','PaperLib','claims','8def00cac79394a1b846d4fbb37057c2f97fa4e794d2dab9b904191b6de7ff9a');
INSERT INTO "meta_claims" VALUES(2382,'paper-53','The Higgs mechanism is identified with the VOA excited weight 5 = Higgs (Paper 16). The mass is anchored by construction: m_H = 5 · κ · SCALE = 125.25 GeV.','D','PaperLib','claims','92c4fc76b1c28304a028e4d37db52bbd1acefb0972492cb2d027ef90ac4062b0');
INSERT INTO "meta_claims" VALUES(2383,'paper-53','The Higgs weight w = 5 is the first excited weight above the vacuum w = 0 that produces a stable particle. Lower weights (w = 1, 2, 3, 4) are not stable particles in the SM.','D','PaperLib','claims','cfb0eb848fd9a55e8aa4fd1cc8acf0fa384e64cf57c8922de5639654afa3ae7e');
INSERT INTO "meta_claims" VALUES(2384,'paper-53','The Higgs mass 125.25 GeV = 5 × κ × SCALE emerges from the chart structure (Paper 4, Theorem 5.1): the chart is the lattice code chain 1→3→7→8→24→72, and the Higgs weight w = 5 is the 5th rung of the ladder.','D','PaperLib','claims','f7229cd79dddd2a85543269508a03c89c24b6f557b17536584500f8fcccc582f');
INSERT INTO "meta_claims" VALUES(2385,'paper-53','In the LCR cosmological framework, the Higgs field is the observer: the Big Bang = Higgs field observing itself. The Higgs field''s self-interaction potential is the self-observation operator.','I','PaperLib','claims','716d11b7f9bdf4d46e7d91b1ad6b22a862c567eb4e58c61d9c92b7ae3ca6d5fc');
INSERT INTO "meta_claims" VALUES(2386,'paper-53','The Higgs mass 125.25 GeV is the first stable mass produced by the VOA correction structure. The Higgs is the first stable particle after the Big Bang.','D','PaperLib','claims','0c120b7954ebdd6c06a6ccf1055fe77cfcdefb1abc6035529457fdb1f39febef');
INSERT INTO "meta_claims" VALUES(2387,'paper-53','The Higgs self-coupling λ ≈ 0.13 is the observer coupling: it measures the strength of the Higgs field''s self-observation.','I','PaperLib','claims','54595ddf263f1a4769dc828487d55bd44372eff65a5e56aa25698c71b5265f0d');
INSERT INTO "meta_claims" VALUES(2388,'paper-53','The Higgs field''s SU(2) doublet structure is connected to the J3(O) atlas (Paper 4, Theorem 3.1) via the exceptional Jordan algebra. The Higgs doublet is a point in the J3(O) manifold.','D','PaperLib','claims','5a8219802a780dc88ac921cb1690ee57a3c340f3bd80441f0f7cf3f74e270dbb');
INSERT INTO "meta_claims" VALUES(2389,'paper-53','⁴ for the off-diagonal embedding X(φ). The potential is V(φ) = −½μ²tr(X²) + ¼λtr(X⁴).','D','PaperLib','claims','e4d710cd8dc9b29c196a68a0b8ab1048b77f3b60da72cb753c883c5c7c3b1075');
INSERT INTO "meta_claims" VALUES(2390,'paper-53','The quartic coupling λ_SM = m_H²/(2v²) ≈ 0.13 is computed from the trace-form potential and is consistent with PDG 2024.','D','PaperLib','claims','6c5f1ab6a596a802e0402157be28e1c8d7ca41ca9de0561da0125979cc0e07a6');
INSERT INTO "meta_claims" VALUES(2391,'paper-53','The Higgs potential is the geodesic distance from the vacuum to the Higgs state in the J3(O) manifold, where the metric is the Freudenthal metric g_ij = tr(∂_i X ∘ ∂_j X). The Christoffel symbols are the gauge couplings (Paper 56).','I','PaperLib','claims','740a49f3071b676e120efa9aa46a5b21703723d6b99c460346af0f73566d5850');
INSERT INTO "meta_claims" VALUES(2392,'paper-53','The Higgs field''s SU(2) doublet structure is connected to the E6/E8 exceptional structure via the lattice code chain. The Higgs doublet is the 2-dimensional representation of SU(2) that appears in the E6 root system decomposition.','D','PaperLib','claims','5665411d50343af7678e53617d4da5d8c58ed8d0988fa26fdfd6e15dfc92c4a2');
INSERT INTO "meta_claims" VALUES(2393,'paper-53','The Higgs sector VOA weights are structurally derived: photon γ = 0.0, W± = 3.5, Z = 4.0, Higgs H = 5.0. The Higgs mass m_H = 5 · κ · SCALE = 125.25 GeV is the anchor.','D','PaperLib','claims','fe53b90b5e148b58560b15861fe33fba3664a496266d907079e8e69309692ff6');
INSERT INTO "meta_claims" VALUES(2394,'paper-53','The Higgs self-coupling λ is related to the VOA weight difference: λ = ½(w_H/v)² · (κ · SCALE)² ≈ 0.129, consistent with the SM value λ ≈ 0.13.','D','PaperLib','claims','1f58ca2167a5e9fd4ba10877583547e5232cc4d73c612f7391bff8759f8ad61b');
INSERT INTO "meta_claims" VALUES(2395,'paper-53','The SM mapping file for LCR-53 does not exist; 12 claimed rows are inferred.','D','PaperLib','claims','3b4bb3d8b82990da1db917be4d219eb393cb3603d02649c356727bef27053bc5');
INSERT INTO "meta_claims" VALUES(2396,'paper-53','The W/Z VOA weights are open (not yet assigned), and the cosmological interpretation of the Higgs as observer is the user''s framework, not yet derived from first principles.','D','PaperLib','claims','b5cdbf23e99bb82727846e1a821d736c6608c1a2e98503b2ce6da40a2742fcea');
INSERT INTO "meta_claims" VALUES(2397,'paper-54','The VOA on the chart has excited states at weights 0, 5, 6, 7, 8, 9, ... The 5th excited state (weight 5) is the Higgs boson.','D','PaperLib','claims','5e4d7d5236d0088b3a756daf9f8187785a7daca075f2a48e260a8453d723db4f');
INSERT INTO "meta_claims" VALUES(2398,'paper-54','The VOA weights on the chart are discrete integers: 0 (vacuum), 5 (Higgs), 6 (Higgs-like), 7, 8, 9, ... The weights are the natural grading of the lattice.','D','PaperLib','claims','a90d6e235b06f005c03218b0232f60ba44ac581ef3c75078160b7d589c42a86b');
INSERT INTO "meta_claims" VALUES(2399,'paper-54','The VOA weights are the lattice code chain (Paper 4, Theorem 5.1): the weights are the rungs of the ladder that correspond to the physical states. The chain 1→3→7→8→24→72 is the underlying structure.','D','PaperLib','claims','64ed49a5a27313cd040d68afc16b4b5c001e3a620a0ea0931a7b2dca475c5669');
INSERT INTO "meta_claims" VALUES(2400,'paper-54','The 5th excited state of the VOA is the Higgs. The mass is anchored by construction: m_H = 5 · κ · SCALE = 125.25 GeV.','D','PaperLib','claims','2bad4ad494382cefb5723b6116604e9ec223afdcd0065681647feed00bdce02d');
INSERT INTO "meta_claims" VALUES(2401,'paper-54','The Higgs is the first massive excitation of the VOA: the vacuum (w = 0) is massless; the Higgs (w = 5) is the first state with a non-zero mass.','D','PaperLib','claims','b59dac2f4ba80c6e5bf723e93cca8ec8c9c9661efd2a58f6f7663215517979d7');
INSERT INTO "meta_claims" VALUES(2402,'paper-54','The Higgs mass 125.25 GeV is a prediction of the VOA structure: it is the mass of the 5th excited state, with the SCALE calibrated by the Higgs mass itself (circular anchor).','D','PaperLib','claims','37c51e33fe2ca6aa42712ff77336b471b9e74057076db8a42f41f1e27587dad1');
INSERT INTO "meta_claims" VALUES(2403,'paper-54','The Higgs weight w = 5 is consistent with the Monster McKay row (Paper 90, Theorem 2.1): the McKay-Thompson coefficients c_n for n = 5 match the Higgs mass.','I','PaperLib','claims','4b3c3f08b4205ada5beddbf38b428bb3d58da17843b6084cf0858a82179b87fa');
INSERT INTO "meta_claims" VALUES(2404,'paper-54','The Monster VOA has coefficients that match the McKay-Thompson series. The VOA on the chart is a restriction of the Monster VOA to the chart''s states.','D','PaperLib','claims','68447199e1d1a5eb0b3ff64cd09d3aad978c965800b347caaddba4e02272b148');
INSERT INTO "meta_claims" VALUES(2405,'paper-54','The Monster VOA is the ceiling structure of the LCR framework: it is the maximal VOA that contains all the physical states as restrictions.','D','PaperLib','claims','31a0deaf1def310a450a103676dacddfe35d76a401401e41a3da218b037d2b4c');
INSERT INTO "meta_claims" VALUES(2406,'paper-54','The Higgs weight w = 5 is connected to the lattice code chain 1→3→7→8→24→72. The natural unit is 25.05 GeV; the Higgs is 5 units.','D','PaperLib','claims','5cd566b2c3d30c6fc7aac6825d8ac751e6382a0c9f53d48e137cd102a049e3dd');
INSERT INTO "meta_claims" VALUES(2407,'paper-54','The VOA excited state mass spectrum predicts confirmed states (w = 0, 3.5, 4.0, 5.0, 7.0) and open BSM candidates (w = 6.0, 8.0, 9.0, 10.0).','D','PaperLib','claims','92bbd0e3f8e96d4d6a086a610ce7adc7928c8f7ea8ad51111d2c0a88992fb655');
INSERT INTO "meta_claims" VALUES(2408,'paper-54','The SM mapping file for LCR-54 does not exist; 3 claimed rows are inferred.','D','PaperLib','claims','78ef24fd5c959098f594625eaa096735769db45977ba6796d532b0ef7ec8437a');
INSERT INTO "meta_claims" VALUES(2409,'paper-55','The vacuum stability requires λ > 0 at all scales. The SM renormalization group flow gives λ → 0 at ~10^10 GeV (the metastability scale).','D','PaperLib','claims','1f7b6256dc8cbf305eb9c436af1b1cfdec01cf1f219b29131e8b7d5da311d8e3');
INSERT INTO "meta_claims" VALUES(2410,'paper-55','The metastability scale is ~10^10 GeV, far above the electroweak scale (174 GeV) but far below the Planck scale (10^19 GeV).','D','PaperLib','claims','06d018dca375bb82b10f118ba3e579098f14e2e2bf3afe5ee01db37d2f51f2f1');
INSERT INTO "meta_claims" VALUES(2411,'paper-55','= v/√2 = 174 GeV.','D','PaperLib','claims','9657e739078d932d8d63d63b9124bccbb5017caba15409dc9c85efad30bccebb');
INSERT INTO "meta_claims" VALUES(2412,'paper-55','The SM vacuum is metastable: the Higgs potential is bounded from below at the electroweak scale but becomes unbounded at high scales. The metastability is a consequence of the top quark Yukawa coupling.','D','PaperLib','claims','967305245b4a675a3a68695131cb4dbd6b8ad6e6b5d26322f5e1ecfe0037590d');
INSERT INTO "meta_claims" VALUES(2413,'paper-55','The lifetime of the metastable vacuum exceeds the age of the universe (~13.8 Gyr), so the vacuum is effectively stable for all practical purposes.','D','PaperLib','claims','06107e4ecf95f0711520c5eba25d05cfc27c173cc4cfee75013cdac1320d4a23');
INSERT INTO "meta_claims" VALUES(2414,'paper-55','In the LCR framework, the metastability is a boundary repair phenomenon (Paper 5): the electroweak scale is the "repaired" boundary where λ > 0; the high-scale region is the "unrepaired" region where λ < 0.','D','PaperLib','claims','51b976c653aaafe581b01d3df5cd93bd815d8e5f21454ea3bd5a437c2046693b');
INSERT INTO "meta_claims" VALUES(2415,'paper-55','The boundary repair operation (Paper 5) is the RG flow that keeps λ positive up to the metastability scale. The repair curvature K(v) is the RG flow of λ.','D','PaperLib','claims','ef82b5d454dca1b86c04abd8c1ced65b5c9aad6f6e6397fcd8b2c8d4ac474653');
INSERT INTO "meta_claims" VALUES(2416,'paper-55','The metastability scale (~10^10 GeV) is the repair boundary: beyond this scale, the repair curvature is insufficient and the boundary fails.','D','PaperLib','claims','d038751b5c8e0ffa22dc69fbbd0d9eb610f7a86585c6d2ce264ddde48e87340f');
INSERT INTO "meta_claims" VALUES(2417,'paper-55','The vacuum energy is the mass residue (Paper 16) of the boundary repair: the energy that remains after the repair is the residual energy of the vacuum. The cosmological constant is this residual energy.','D','PaperLib','claims','80656a8af3103799a95764cc152712753e6e86c8b388fc0a929db32fbcd093ec');
INSERT INTO "meta_claims" VALUES(2418,'paper-55','The cosmological constant problem is the discrepancy between the Higgs vacuum energy (~10^56 times the observed cosmological constant) and the observed dark energy density.','D','PaperLib','claims','0bea08d77476d8f8710487748e7f2c46185791e992fff1d2a856e024a5c2b18d');
INSERT INTO "meta_claims" VALUES(2419,'paper-55','In the LCR framework, the vacuum energy cancellation is the boundary repair (Paper 5) that removes the divergent zero-point energy. The zero-point energy is the sum of the VOA weights: Σ_w w · κ · SCALE.','D','PaperLib','claims','c1ad3e4ba346692a906e7c1ba16e82ff7d80abfb75d7d977ab001d928752a2ec');
INSERT INTO "meta_claims" VALUES(2420,'paper-55','= v/√2 when the VOA weight w = 5 is the lowest excited weight with a stable mass.','D','PaperLib','claims','d834ceedb5868f1999b2d65964ce9e16a9082aa1bbc1eae2cec65eeb42dd8b93');
INSERT INTO "meta_claims" VALUES(2421,'paper-55','The SM vacuum is metastable at high energy because the Higgs self-coupling λ runs to negative values at high energy (~10^10 GeV). In the LCR framework, this corresponds to a VOA weight w > 5 having a lower energy state.','D','PaperLib','claims','e116f1aef8db533a589cf0119063a7eaa5a9e559538cd6420537f3fb53360d83');
INSERT INTO "meta_claims" VALUES(2422,'paper-55','The vacuum stability boundary is the w = 5 boundary: the vacuum is stable for w ≤ 5 and metastable for w > 5.','D','PaperLib','claims','cdaf3656f77b7a7a303564ea6bf3fbf91ce371b4479f94172417754687186e13');
INSERT INTO "meta_claims" VALUES(2423,'paper-55','The top quark Yukawa coupling y_t ≈ 1 drives the RG flow. In the LCR framework, the top quark is the VOA weight w = 7 (open assignment). The Yukawa coupling is the coupling between the top quark (w = 7) and the Higgs (w = 5).','D','PaperLib','claims','dd2683c5a46eeaacb42b0a80f0354c3c2c87c874e1dcef1df32d88180dbcca62');
INSERT INTO "meta_claims" VALUES(2424,'paper-55','The top quark mass m_t ≈ 173 GeV is the VOA weight w = 7: m_t = 7 × 25.05 ≈ 175.35 GeV, close to the measured 173 GeV.','D','PaperLib','claims','e891a327777708278ddffa1358530895b1828b25ffe65f6b50a8306d8d418200');
INSERT INTO "meta_claims" VALUES(2425,'paper-55','The SM mapping file for LCR-55 does not exist; 5 claimed rows are inferred.','D','PaperLib','claims','508d55b6aa533a1b3658061bf174535fcd6b9a223dbf55391eecd1338130e28e');
INSERT INTO "meta_claims" VALUES(2426,'paper-56','The Higgs couplings are proportional to the VOA weight differences: g_f = y_f × v = w_f × κ × SCALE · v/v.','D','PaperLib','claims','be5750b26f61edc09ad6a16a9dbf28adcb29c814167074fc4c93d6096b46b88d');
INSERT INTO "meta_claims" VALUES(2427,'paper-56','The Higgs coupling to a fermion f is g_f = m_f × v/v. The coupling to a boson is g_V = m_V² × v/v.','D','PaperLib','claims','7fd8bc171e730740be6c9c8d920c2437a011ec6b9ba36bc6fdb5d62b6e0c7b2a');
INSERT INTO "meta_claims" VALUES(2428,'paper-56','In the LCR framework, the Higgs couplings are determined by the VOA weight differences between the Higgs (w = 5) and the coupled state (w_f).','D','PaperLib','claims','891f98cb84564cd4803d45beb2dc1b5b0b8c4a9fbb58b57ab97ed7b255c5d1c9');
INSERT INTO "meta_claims" VALUES(2429,'paper-56','gives the coupling strength: g_f = Δw × κ × SCALE × v/v.','D','PaperLib','claims','96765b7b3fc857e6886c202ad1bc6f218289758fee2e501d7ec7a40c19ccd185');
INSERT INTO "meta_claims" VALUES(2430,'paper-56','The Higgs coupling to the top quark (w = 7) is the strongest: g_t = (7 − 5) × κ × SCALE = 2 × 25.05 = 50.10 GeV.','D','PaperLib','claims','e761e2ed916db3d7bfdca7b4542a80c3f6ff651956a06aeafea76d1d9c7c1d34');
INSERT INTO "meta_claims" VALUES(2431,'paper-56','The Higgs coupling to the W boson (w = 3.5) is g_W = (5 − 3.5) × κ × SCALE = 1.5 × 25.05 = 37.58 GeV.','D','PaperLib','claims','ee5d9fd257e3073f99d24684ff9a1b0aba0f7dfe52b657e639adc88df73ff5f9');
INSERT INTO "meta_claims" VALUES(2432,'paper-56','The Higgs self-coupling λ = m_H² / (2v²) = 0.13. In the LCR framework, λ = (5 × κ × SCALE)² / (2v²).','D','PaperLib','claims','c497d62abfcc7b77405dfba99e6037298c48824f5b79a7063b5796eb87d76fd4');
INSERT INTO "meta_claims" VALUES(2433,'paper-56','The Higgs couplings are the geodesic distances on the J3(O) manifold (Paper 53) between the Higgs state (w = 5) and the coupled state (w_f).','D','PaperLib','claims','f6782029b1d93bdb1aef34ed5bbc909c5e5836f882d7a37bd68929f28ffe3c33');
INSERT INTO "meta_claims" VALUES(2434,'paper-56','The Higgs couplings are the lattice code chain distances (Paper 4): the coupling to a state at weight w_f is the distance in the chain from the Higgs node to the node at w_f.','D','PaperLib','claims','d9135bbde12033dfd0f08fe03f68ff59e55b67c6b2e7c6ef13149c24db2daae5');
INSERT INTO "meta_claims" VALUES(2435,'paper-56','The Higgs coupling to the photon (γ) is loop-induced (γγ and γZ) and not directly proportional to a VOA weight difference.','D','PaperLib','claims','460458e301a33af34879670d600339d806a120ec141d110b6e41318f54a89c66');
INSERT INTO "meta_claims" VALUES(2436,'paper-56','The Higgs couplings to gluons (gg) are also loop-induced (via top quark loop) and not directly proportional to a VOA weight difference.','D','PaperLib','claims','b373902939a489befb6045b32cd7222c23036209dbfa8dc9b1d357f9c7c7964a');
INSERT INTO "meta_claims" VALUES(2437,'paper-56','The Higgs decay widths are proportional to the square of the couplings: Γ_f = g_f² × m_H / (8π).','D','PaperLib','claims','04d27e9e83dd8c4c54aacc6c933815288f930eb9173dae3a5ffc56342f225989');
INSERT INTO "meta_claims" VALUES(2438,'paper-56','The Higgs branching ratios are determined by the VOA weight differences: BR_f = Γ_f / Γ_total.','D','PaperLib','claims','1836b0e35b8a0c335e70986c94c2d84f8ba89748e25f25f4d338f7a3d0d3e0d2');
INSERT INTO "meta_claims" VALUES(2439,'paper-56','The Higgs coupling deviations from SM predictions (e.g., in 2HDM) are mapped to VOA weight shifts: Δw = 6 would give a second Higgs with different couplings.','D','PaperLib','claims','11e1ed62009d92cdee824c18222ebcd66aa32e746a26e7e1d9867ac11d74329e');
INSERT INTO "meta_claims" VALUES(2440,'paper-56','The SM mapping file for LCR-56 does not exist; 4 claimed rows are inferred.','D','PaperLib','claims','4b54bbf9940c74482c355b62bf936f02fec899dbc182f11388b072d2110384d5');
INSERT INTO "meta_claims" VALUES(2441,'paper-57','Mesons are quark-antiquark bound states (q-q̄); baryons are 3-quark bound states (qqq). The hadron spectrum is the explicit mass and quantum number spectrum.','D','PaperLib','claims','69b6e7d1d3db95b339906d1d34d82651e40d83186e56314308f88e694c523440');
INSERT INTO "meta_claims" VALUES(2442,'paper-57','The hadron spectrum is the QCD bound state spectrum: the strong force binds quarks into hadrons; the spectrum is the energy levels of the bound states.','D','PaperLib','claims','4b9711b394d0e0900ee7a38c6648640c2a730000d4231b00f584f0a8c088392e');
INSERT INTO "meta_claims" VALUES(2443,'paper-57','In the LCR framework, the hadron spectrum is the spectrum of the SU(3) color lattice (Paper 4): mesons are singlet and octet representations; baryons are singlet, octet, and decuplet representations.','D','PaperLib','claims','19ee4f4f856555e38cd3789a0982e89f8476f3e70f75e625673dbafdc0800938');
INSERT INTO "meta_claims" VALUES(2444,'paper-57','The quark model (Gell-Mann, Zweig 1964) classifies hadrons by quark content. Mesons: 3 ⊗ 3̄ = 1 ⊕ 8; baryons: 3 ⊗ 3 ⊗ 3 = 1 ⊕ 8 ⊕ 8 ⊕ 10.','D','PaperLib','claims','818f6c282bc14cac35d5aec9142b705790434b197e587308c5ecd0bbe08f8822');
INSERT INTO "meta_claims" VALUES(2445,'paper-57','The meson nonet (9 mesons) is the singlet + octet: π (triplet), K (doublet), η (singlet), η'' (singlet).','D','PaperLib','claims','a225ba46cfdef70fc51bbb4611ea10a03b5e064c2678bb36198081244bf3674c');
INSERT INTO "meta_claims" VALUES(2446,'paper-57','The baryon decuplet (Δ, Σ*, Ξ*, Ω) is the 10 representation of 3 ⊗ 3 ⊗ 3.','D','PaperLib','claims','3625f17cf3742ee89c36bf2f299fe7e3939ac251563820c6ffe4381733f04512');
INSERT INTO "meta_claims" VALUES(2447,'paper-57','The D4 codec (Paper 4, Theorem 5.1) encodes the 8 gluons as the 8 roots of the SU(3) adjoint representation. The D4 root system has 24 roots; the SU(3) subalgebra has 8 roots.','D','PaperLib','claims','a2cd78b34149f2e16d7c3ab25c58ac49986c8dc7f62f75624044720b9b9d281a');
INSERT INTO "meta_claims" VALUES(2448,'paper-57','The QCD running coupling α_s(Q²) = 4π/(β₀ ln(Q²/Λ²_QCD)) decreases with energy (asymptotic freedom).','D','PaperLib','claims','7bae434e44e3d43e56d068ad29f9667d5f3cea18d109281dfdeb2b5389daec8a');
INSERT INTO "meta_claims" VALUES(2449,'paper-57','Asymptotic freedom is the boundary repair (Paper 5) at high energy: the color charge is the boundary type, and the running coupling is the repair curvature that removes the color charge at high scales.','D','PaperLib','claims','7870f4f236a4894b0f89d8b550789f02c15c31f5f873750766c422b9219be8c0');
INSERT INTO "meta_claims" VALUES(2450,'paper-57','Perturbative QCD is the expansion in the repair curvature (Paper 5): Feynman diagrams are successive approximations to the boundary repair, and α_s is the expansion parameter.','D','PaperLib','claims','a80805c95eadbeb7536df361f4e59812a40a82b942aed37369d3dcc74c5a2130');
INSERT INTO "meta_claims" VALUES(2451,'paper-57','The lattice code chain 1→3→7→8→24→72 underlies the QCD scale: 3 valence quarks → "3", 8 gluons → "8", 24 sea-parton species → "24".','D','PaperLib','claims','ade908f1c0281b7791533b0bd8ba2faf404f978ca641a0b43210f847ce2d5bb4');
INSERT INTO "meta_claims" VALUES(2452,'paper-57','The hadron masses are derived from the VOA weights of the constituent quarks: m_meson = w_q + w_q̄; m_baryon = w_q₁ + w_q₂ + w_q₃.','D','PaperLib','claims','8951141f257f0467d5229d58cb292a742226511f28772895a40ad330245ef23d');
INSERT INTO "meta_claims" VALUES(2453,'paper-57','The pion mass is small because the up and down quark VOA weights are small.','D','PaperLib','claims','ff9295937b433b423b02eba384ae13e057c1c8f2234a50408946bead3728be7c');
INSERT INTO "meta_claims" VALUES(2454,'paper-57','The Ω baryon mass is large because the strange quark VOA weight is large.','D','PaperLib','claims','c86812a1981a8bdd2524f8d3561f3e47636c4f3230459a443dc30e40824fec71');
INSERT INTO "meta_claims" VALUES(2455,'paper-57','The SM mapping file for LCR-57 does not exist; 6 claimed rows are inferred.','D','PaperLib','claims','41b75899dbaf560856bbc4a29a0aaaa56983e5c127b023df6212c212cf137896');
INSERT INTO "meta_claims" VALUES(2456,'paper-58','The parton distribution functions (PDFs) f_i(x, Q²) give the probability density of finding parton i carrying momentum fraction x at resolution scale Q.','D','PaperLib','claims','d219876b2d923455b2e34f7341cb2e5ed3452466c15a2c9386230306df1c8c7c');
INSERT INTO "meta_claims" VALUES(2457,'paper-58','The DGLAP equations govern the scale dependence of PDFs.','D','PaperLib','claims','f50dafb72aa81ee0ccbe408e13bd4ca8ad3f50d39eeb39e35c8f395cdff10e33');
INSERT INTO "meta_claims" VALUES(2458,'paper-58','The proton PDFs decompose into 3 valence quarks (uud), a sea of q-q̄ pairs, and 8 gluon polarisations. The 3 valence quarks map to the "3" in the lattice code chain, the 8 gluons to the "8", and the 24 sea-parton species to the "24".','D','PaperLib','claims','5a1d8a14fc0bb9bb9a0b58bc560c099dd6691da463afd28d5edf575dcd161b43');
INSERT INTO "meta_claims" VALUES(2459,'paper-58','The hadron spectroscopy (Paper 57) is the boundary of the PDF evolution: hadrons are the color-singlet states that emerge at low Q, and PDFs are the parton-level description that resolves the hadron boundary.','D','PaperLib','claims','9e59c819adeb1f250790da325f985569deb8eb7522423259440a3a2f1cb8269a');
INSERT INTO "meta_claims" VALUES(2460,'paper-58','In the LCR framework, the proton is a typed boundary (Paper 5) whose internal structure is repaired by the PDFs. The repair curvature at the parton level is the DGLAP splitting kernel P_ij(z); the boundary type is the proton quantum number (B=1, Q=1, I₃=+½).','D','PaperLib','claims','703afdc9500192e01b6d7207706a3f9edc75fda6408472912391b49568b217b3');
INSERT INTO "meta_claims" VALUES(2461,'paper-58','The measured PDFs (CTEQ, MSTW, NNPDF) are the receipts (Paper 11) of the QCD repair process. Each PDF fit is a master-receipt stack entry that records the boundary state at a given scale Q.','D','PaperLib','claims','3c42c5d4b481cc8baf823c48483f753d4b03bc63614ecb5e4ff9ec3f098eac1c');
INSERT INTO "meta_claims" VALUES(2462,'paper-58','The mesons (q-q̄) and baryons (qqq) (Paper 57) are the boundary types of the QCD typed boundary: mesons are the color-singlet quark-antiquark boundaries, and baryons are the color-singlet 3-quark boundaries.','D','PaperLib','claims','d1a5bfdd4d043e541a5de63d2a633f0871645b63d90bedb1f5cfe5670d20e564');
INSERT INTO "meta_claims" VALUES(2463,'paper-58','The lattice code chain 1→3→7→8→24→72 underlies the parton counting: 1 = proton, 3 = valence quarks, 7 = active parton species (3 quarks + 4 sea), 8 = gluon polarisations, 24 = sea-parton species (6 flavours × 4 helicities), 72 = total charged tracks in high-multiplicity event.','D','PaperLib','claims','ab4857bf5ffc8a171cd86fa0343cb3e79e0d2121f7759e4415333539c297dfe0');
INSERT INTO "meta_claims" VALUES(2464,'paper-58','The PDF evolution is the boundary repair from the hadron boundary (low Q) to the parton boundary (high Q). The DGLAP equations are the repair curvature that removes the hadron boundary and reveals the parton boundary.','D','PaperLib','claims','614ad0f42f052735f693c958f06b78efc44abd5ff7f9a1bb0f1b4aa59c6b0ed9');
INSERT INTO "meta_claims" VALUES(2465,'paper-58','The proton mass is the sum of the valence quark VOA weights plus the sea contribution: m_p = w_u + w_u + w_d + w_sea.','D','PaperLib','claims','48c65be19e3897e0cca097a2672ab68d0bf8807d0f23e32975566fcafcd94617');
INSERT INTO "meta_claims" VALUES(2466,'paper-58','The VOA natural energy scale 25.05 GeV (Paper 16) sets the hard-scale boundary for PDF evolution: Q² >> (25.05 GeV)² is the perturbative region; Q² << (25.05 GeV)² is the non-perturbative region.','D','PaperLib','claims','a2c0943f2799f777f3f3d212a6cd14069f27aafbdc5932badf010b274a3348fd');
INSERT INTO "meta_claims" VALUES(2467,'paper-58','The SM mapping file for LCR-58 does not exist; 5 claimed rows are inferred.','D','PaperLib','claims','4a4d69ec4bde7ae7eb1505a03de3d1c86453caec4faa338c0702f12d5dcd97c0');
INSERT INTO "meta_claims" VALUES(2468,'paper-59','A jet is a collimated spray of hadrons produced by the hadronisation of a high-energy quark or gluon. The anti-kT algorithm clusters particles by the distance measure d_ij = min(p_T,i^-2, p_T,j^-2) ΔR_ij²/R².','D','PaperLib','claims','1c98330733c22cfdcab106ecb0c61d80d22daa7cab9928b5a4f80777e5c07480');
INSERT INTO "meta_claims" VALUES(2469,'paper-59','The anti-kT algorithm is infrared and collinear safe.','D','PaperLib','claims','9acab183726f2ccaa18273d4bf889d6f04220aa7156249415668a4506c449aed');
INSERT INTO "meta_claims" VALUES(2470,'paper-59','In a typical high-energy event the jet multiplicity follows the ladder 1→3→7→8→24→72: 1 hard parton, 3 jets, 7 hadrons, 8 stable species, 24 final-state particles, 72 charged tracks.','D','PaperLib','claims','43a9c2552dae8602de8066707457f0cb749b3eb76ddd8ce3d96be9e7065a880b');
INSERT INTO "meta_claims" VALUES(2471,'paper-59','The anti-kT algorithm is the computational repair operator (Paper 5): it clusters final-state particles into jets, reconstructing the original parton boundary from the hadron-level receipts.','D','PaperLib','claims','b232accf0ccb7d71cf6ef88039c5557b556c99d44763c2517b2a3d2d1b19c6c7');
INSERT INTO "meta_claims" VALUES(2472,'paper-59','The fragmentation functions D_i^h(z, Q²) give the probability density that parton i fragments into hadron h with momentum fraction z at scale Q. They satisfy the momentum sum rule Σ_h ∫_0^1 dz z D_i^h(z, Q²) = 1.','D','PaperLib','claims','2e0e24d989b040c059ca353a42fc7acfcd11d62f4402410b212742c3304d6e43');
INSERT INTO "meta_claims" VALUES(2473,'paper-59','The fragmentation functions are the bridge artifact (Paper 8) between the parton-level boundary and the hadron-level boundary. The bridge is one-way: partons → hadrons; the reverse is forbidden by confinement.','D','PaperLib','claims','c52a6785aed180d7ce72bbab6ae3b39c5ca22e09a0c86f73bb71f557742fe37f');
INSERT INTO "meta_claims" VALUES(2474,'paper-59','The fragmentation functions are the receipts (Paper 11) of the boundary repair: they record the state of the hadron-level boundary after the parton-level boundary has been repaired.','D','PaperLib','claims','d792afc7dbf380d194e06e96ba0626f1c3d336bf01d1a09900f76ce3f1b28b0b');
INSERT INTO "meta_claims" VALUES(2475,'paper-59','In the LCR framework, a jet is a typed boundary repair (Paper 5): the high-energy parton boundary is repaired by the strong force into a cluster of hadrons.','D','PaperLib','claims','bc5434db4c3783a90bfcd654ee92d1d7ebdb9a66e5ba6a19e1d7d986a68cb3bd');
INSERT INTO "meta_claims" VALUES(2476,'paper-59','The QCD phase transitions (quark-gluon plasma, color superconductivity) are the boundary repair at high temperature: the phase transition is the repair that removes the confinement boundary and restores the quark-gluon plasma.','D','PaperLib','claims','938c5c3f4f7562dea7d388b9c86e445ce7e9d844e5f0832f39b2a81c281a2f5d');
INSERT INTO "meta_claims" VALUES(2477,'paper-59','Lattice QCD (Paper 60) is the discrete model of the phase transition: the lattice is the discrete carrier, and the continuum limit is the boundary repair.','D','PaperLib','claims','e98e88b218056a0038e3b2988021fed62896e8240d36b5d16d404d589301de1d');
INSERT INTO "meta_claims" VALUES(2478,'paper-59','The lattice code chain 1→3→7→8→24→72 underlies the multiplicity structure: a typical event evolves from 1 initial parton through 3 partons (3-jet), 7 hadrons in the core, 8 stable species, 24 final-state particles, up to 72 total charged tracks.','D','PaperLib','claims','2ee1b89cf176400c1731a1bc3b8645188699566720a1f3385d2f8f13d6d7c554');
INSERT INTO "meta_claims" VALUES(2479,'paper-59','The SM mapping file for LCR-59 does not exist; 4 claimed rows are inferred.','D','PaperLib','claims','4951288b7a3b59a2f41a019ea4da4c5cafce3f08d24f5e9908030ad75158348a');
INSERT INTO "meta_claims" VALUES(2480,'paper-60','Lattice QCD discretises space-time on a 4D hyper-cubic lattice with spacing a. The gauge action is the Wilson plaquette action S_G = β Σ_x Σ_{μ<ν} (1 − (1/3)ℜ Tr P_{μν}(x)), where β = 6/g².','D','PaperLib','claims','b9e1a84404bbdba0c4a22d14d40c8ba65771598acdf7863d32b02edb765f5129');
INSERT INTO "meta_claims" VALUES(2481,'paper-60','The physical observables are obtained by taking the continuum limit a → 0 while keeping the lattice volume L⁴ large enough to suppress finite-size effects.','D','PaperLib','claims','17b0535c81e79dccd30fc24fb143d79dec95e37cf31c93cb450e543eb2eb3465');
INSERT INTO "meta_claims" VALUES(2482,'paper-60','In the LCR framework, the lattice is the discrete–continuous bridge (Paper 8): the discrete side is the lattice gauge field U_μ(x) ∈ SU(3); the continuous side is the gauge potential A_μ(x) in the continuum limit.','D','PaperLib','claims','524733f6b632f6f92bd83e68c17b6e8652f9a4223321d07a80e45ed1e8b7ab6a');
INSERT INTO "meta_claims" VALUES(2483,'paper-60','The hadron masses computed in lattice QCD are consistent with experiment: m_π ≈ 140 MeV, m_ρ ≈ 770 MeV, m_N ≈ 940 MeV, m_Ω ≈ 1672 MeV.','D','PaperLib','claims','67cdc86f2b6ac8b1a8408a7463b41ece01107eccf5581a1d04f703d5cb0adadf');
INSERT INTO "meta_claims" VALUES(2484,'paper-60','The lattice hadron masses are the receipts (Paper 11) of the non-perturbative QCD repair. Each mass is a verifiable record of the carrier state at the confinement boundary.','D','PaperLib','claims','7f229fe326d660846db593942fea4fe12349c52c739b386f268f3732375063ce');
INSERT INTO "meta_claims" VALUES(2485,'paper-60','In the LCR framework, the hadron masses are the receipts (Paper 11) of the boundary repair (Paper 5): each mass is the verifiable record of the repair process that confined the quarks into hadrons.','D','PaperLib','claims','e32f9bcd5d71249969b05204a1111bb01e0687d5bb0a4d5804989ac9e3d161dc');
INSERT INTO "meta_claims" VALUES(2486,'paper-60','The lattice spacing a is the natural unit of the LCR substrate at the QCD scale; the continuum limit a → 0 is the boundary repair (Paper 5) that removes the discretisation.','D','PaperLib','claims','2e2cc14a54f62d84d2c5c199b4b06116a7aaf8ba491ec43a337adc6e8b9030a4');
INSERT INTO "meta_claims" VALUES(2487,'paper-60','The lattice code chain 1→3→7→8→24→72 underlies the lattice architecture: the 4D lattice is a subspace of the 8D lattice; the 24 link variables per site correspond to the "24"; the 72 hadron states are the target observables.','D','PaperLib','claims','3c6a594b82746882e7aadf229ecfd64daa0df65ed6ded0c5bc312a21968fab18');
INSERT INTO "meta_claims" VALUES(2488,'paper-60','The F4 action (Paper 4, Theorem 5.1) constrains the parton dynamics: the F4 root system is the symmetry of the lattice action, and the parton dynamics are the projections of the F4 action onto the physical subspace.','D','PaperLib','claims','c8b4932e0e7e6a4b0348beda3e136ff53c284936469c82069caf728ea6d678b1');
INSERT INTO "meta_claims" VALUES(2489,'paper-60','The QCD at high energy (parton distributions, jet physics) is the continuum limit of the lattice: the high-energy observables are the boundary repair that removes the lattice spacing.','D','PaperLib','claims','8382676ff59a7a5fc7f8c974d28e1848290c05bc55208d73b39d38ea4710faa2');
INSERT INTO "meta_claims" VALUES(2490,'paper-60','The SM mapping file for LCR-60 does not exist; 3 claimed rows are inferred.','D','PaperLib','claims','d4cc2f194cba9a0ce100d8fb1f45d293ffc81d4fc00fd16b47f07c569257ceff');
INSERT INTO "meta_claims" VALUES(2491,'paper-60','Corpus database contains 18 tables, 1665 functions, 31 papers','D','PaperLib','claims','50c945cec6f46eb7dffa89e5f18da90d70552b01da50880a7bd36768f1f01057');
INSERT INTO "meta_claims" VALUES(2492,'paper-60','Corpus verifies itself via receipt system with 43 checks, 0 defects','D','PaperLib','claims','bd73ba59ef996bf8564a42d59b91694929142d3b2f0d0d5e27a577778b0d10e7');
INSERT INTO "meta_claims" VALUES(2493,'paper-60','9 verifiers perform 43 checks with 100% pass rate (0 defects)','D','PaperLib','claims','4359e4aed07d35db74e62b38c56f79fe8cdabb88f1f4482c8d90f70f6c5d7a8f');
INSERT INTO "meta_claims" VALUES(2494,'paper-60','5 calibration suites with 27 parameters all PASS','D','PaperLib','claims','0c0d62c01ffdb59327be447684aae4ab4fbbf1d745bf71f82d929e5fe71934f0');
INSERT INTO "meta_claims" VALUES(2495,'paper-60','Narrative queries: 3/3 PASS','D','PaperLib','claims','8f38653e0761c86477402cef0b6951133ed9a276ddce49dfa5f34cd39b658cbd');
INSERT INTO "meta_claims" VALUES(2496,'paper-60','19 tile families in corpus','D','PaperLib','claims','e99bf80297b05c914d052d051889ee8a8fb75539b1f9bc90a4f1d6dcde1ebb74');
INSERT INTO "meta_claims" VALUES(2497,'paper-60','8 crystallization scenarios in corpus','D','PaperLib','claims','86344c4f61ed8edbe4245a55eca6b297aef78101af73691ccc318edcc6437f69');
INSERT INTO "meta_claims" VALUES(2498,'paper-61','≈ 2.5×10⁻³ eV².','D','PaperLib','claims','c5cc07bebd3772ac05c74d49b0c699fb18bb32d77da282332f8add46ade7c1d0');
INSERT INTO "meta_claims" VALUES(2499,'paper-61','The mass ordering is either normal (m₁ < m₂ < m₃) or inverted (m₃ < m₁ < m₂). The ordering is not yet determined; the CP-violating phase δ_CP is partially constrained.','D','PaperLib','claims','3b3817b97b0b2618a73646e49771eff6da1503bec67674f2af60a9bc96b28b84');
INSERT INTO "meta_claims" VALUES(2500,'paper-61','The sterile neutrino is the BSM dark candidate predicted by the LCR framework: it is the "missing" VOA weight that fills the gap between the light neutrino weights w=1,2,3 and the Higgs weight w=5.','D','PaperLib','claims','126b0cbe10feeba0fa62f999d1ef267ace3567f59372eaa79d8cd83f3a2a82ff');
INSERT INTO "meta_claims" VALUES(2501,'paper-61','The sterile neutrino mass is the mass residue at w=4: m_s = 4κ × 10⁻¹² ≈ 100 eV (suppressed by the cosmological scale 10⁻¹²).','I','PaperLib','claims','f8aac838cc15b61e452805fed00bbbf2a151533aa78afb8c40947434c88d5993');
INSERT INTO "meta_claims" VALUES(2502,'paper-61','The sterile neutrino is a dark matter candidate: its mass is in the warm dark matter range (keV–MeV), and it does not interact via the Standard Model gauge forces.','D','PaperLib','claims','cce51689791a34202c45118a7c74c7d507e9c93464dd8b7ae62b68905dcab760');
INSERT INTO "meta_claims" VALUES(2503,'paper-61','The seesaw mechanism is the VOA weight ladder: the light neutrino masses are m_ν ∼ y²v²/M_R, where v = κ is the VOA natural unit and M_R is the heavy right-handed neutrino mass.','D','PaperLib','claims','6244a1f02248cb2af3a69b78322f18e2f264522903ad458509f0c8662f48af84');
INSERT INTO "meta_claims" VALUES(2504,'paper-61','The heavy mass M_R is the Monster VOA ceiling (Paper 27): M_R ∼ c_max · κ ≈ 10¹² GeV.','D','PaperLib','claims','7aa81049072d7083022149cdf3bd75da920a2065253f4d89fe8df9df632cc99f');
INSERT INTO "meta_claims" VALUES(2505,'paper-61','The PMNS lepton-mixing matrix has 4 parameters: 3 angles (θ₁₂, θ₁₃, θ₂₃) and 1 CP-violating phase δ_CP.','D','PaperLib','claims','a19710ba84096a9b7e3d7cfa44be876a418dc6843c849e309cddd751dee7074e');
INSERT INTO "meta_claims" VALUES(2506,'paper-61','In the LCR framework, the neutrino masses are the mass residue (Paper 16) of the VOA weight assignment: the three light masses correspond to the low VOA weights w=1,2,3.','D','PaperLib','claims','36f5cbacca3f8a462ccdbde31d2830668c6e5f40628e3fcb3e30b9f788cee1d7');
